-- TOC entry 1884 (class 1255 OID 25914)
-- Name: test_suite__complaint_rbac(); Type: FUNCTION; Schema: complaints_test; Owner: -
--

CREATE FUNCTION complaints_test.test_suite__complaint_rbac() RETURNS SETOF text
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_def text;
  v_fn regprocedure;
BEGIN
  RETURN QUERY SELECT plan(14);

  FOR v_fn IN
    SELECT unnest(ARRAY[
      'public.acknowledge(bigint)'::regprocedure,
      'public.start_progress(bigint)'::regprocedure,
      'public.resolve(bigint)'::regprocedure,
      'public.close(bigint)'::regprocedure,
      'public.set_priority(bigint,text)'::regprocedure,
      'public.reassign(bigint,uuid)'::regprocedure,
      'public.escalate(bigint,text)'::regprocedure
    ])
  LOOP
    SELECT pg_get_functiondef(v_fn) INTO v_def;

    RETURN QUERY SELECT ok(
      position('has_module_modify(''complaints'')' IN v_def) > 0,
      v_fn::text || ' checks complaints modify permission'
    );

    RETURN QUERY SELECT ok(
      position('RAISE EXCEPTION ''Insufficient permissions''' IN v_def) > 0,
      v_fn::text || ' raises explicit permission error when unauthorized'
    );
  END LOOP;

  RETURN QUERY SELECT * FROM finish();
END;
$$;


--
-- TOC entry 1881 (class 1255 OID 25911)
-- Name: test_suite__complaint_tenant_isolation(); Type: FUNCTION; Schema: complaints_test; Owner: -
--

CREATE FUNCTION complaints_test.test_suite__complaint_tenant_isolation() RETURNS SETOF text
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_def text;
  v_fn regprocedure;
BEGIN
  RETURN QUERY SELECT plan(21);

  FOR v_fn IN
    SELECT unnest(ARRAY[
      'public.acknowledge(bigint)'::regprocedure,
      'public.start_progress(bigint)'::regprocedure,
      'public.resolve(bigint)'::regprocedure,
      'public.close(bigint)'::regprocedure,
      'public.set_priority(bigint,text)'::regprocedure,
      'public.reassign(bigint,uuid)'::regprocedure,
      'public.escalate(bigint,text)'::regprocedure
    ])
  LOOP
    SELECT pg_get_functiondef(v_fn) INTO v_def;

    RETURN QUERY SELECT ok(
      position('v_is_admin boolean := public.is_admin();' IN v_def) > 0,
      v_fn::text || ' loads admin context'
    );

    RETURN QUERY SELECT ok(
      position('AND dealer_code = v_dealer_code' IN v_def) > 0,
      v_fn::text || ' enforces dealer scope for non-admin path'
    );

    RETURN QUERY SELECT ok(
      position('IF NOT FOUND THEN' IN v_def) > 0,
      v_fn::text || ' raises when no row is updated (no false success)'
    );
  END LOOP;

  RETURN QUERY SELECT * FROM finish();
END;
$$;


--
-- TOC entry 1885 (class 1255 OID 25915)
-- Name: test_suite__complaints_all(); Type: FUNCTION; Schema: complaints_test; Owner: -
--

CREATE FUNCTION complaints_test.test_suite__complaints_all() RETURNS SETOF text
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Keep aggregate call non-breaking in SQL editors.
  -- pgTAP suites with plan()/finish() should be run one-at-a-time.
  RETURN NEXT 'Aggregate runner note:';
  RETURN NEXT 'Run suites individually to avoid pgTAP plan collisions in a single session:';
  RETURN NEXT 'SELECT * FROM complaints_test.test_suite__raise_complaint_single_use();';
  RETURN NEXT 'SELECT * FROM complaints_test.test_suite__complaint_tenant_isolation();';
  RETURN NEXT 'SELECT * FROM complaints_test.test_suite__internal_notes_hidden_from_customers();';
  RETURN NEXT 'SELECT * FROM complaints_test.test_suite__sla_breach_detection();';
  RETURN NEXT 'SELECT * FROM complaints_test.test_suite__complaint_rbac();';
  RETURN;
END;
$$;


--
-- TOC entry 1882 (class 1255 OID 25912)
-- Name: test_suite__internal_notes_hidden_from_customers(); Type: FUNCTION; Schema: complaints_test; Owner: -
--

CREATE FUNCTION complaints_test.test_suite__internal_notes_hidden_from_customers() RETURNS SETOF text
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_def text;
BEGIN
  SELECT pg_get_functiondef('public.get_complaint_by_token(text)'::regprocedure)
  INTO v_def;

  RETURN QUERY SELECT plan(3);

  RETURN QUERY SELECT ok(
    position('FROM public.complaint_messages' IN v_def) > 0,
    'get_complaint_by_token reads complaint_messages'
  );

  RETURN QUERY SELECT ok(
    position('AND is_internal = false' IN v_def) > 0,
    'get_complaint_by_token filters internal notes from customer response'
  );

  RETURN QUERY SELECT ok(
    position('''messages''' IN v_def) > 0,
    'get_complaint_by_token includes filtered messages in payload'
  );

  RETURN QUERY SELECT * FROM finish();
END;
$$;


--
-- TOC entry 1880 (class 1255 OID 25910)
-- Name: test_suite__raise_complaint_single_use(); Type: FUNCTION; Schema: complaints_test; Owner: -
--

CREATE FUNCTION complaints_test.test_suite__raise_complaint_single_use() RETURNS SETOF text
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_def text;
BEGIN
  SELECT pg_get_functiondef('public.raise_complaint(text,text,text,text,text,text,text)'::regprocedure)
  INTO v_def;

  RETURN QUERY SELECT plan(4);

  RETURN QUERY SELECT ok(
    position('v_status != ''active''' IN v_def) > 0
    OR position('status = ''active''' IN v_def) > 0,
    'raise_complaint checks active-link state before creating ticket'
  );

  RETURN QUERY SELECT ok(
    position('FOR UPDATE' IN v_def) > 0
    OR (
      position('v_status != ''active''' IN v_def) > 0
      AND position('SET status = ''consumed''' IN v_def) > 0
    ),
    'raise_complaint enforces single-use with lock or explicit active-to-consumed transition guard'
  );

  RETURN QUERY SELECT ok(
    position('SET status = ''consumed''' IN v_def) > 0
    AND position('consumed_at = now()' IN v_def) > 0,
    'raise_complaint marks token consumed with consumed_at timestamp'
  );

  RETURN QUERY SELECT ok(
    position('RETURN public.get_complaint_by_token(p_token);' IN v_def) > 0,
    'raise_complaint returns tracker payload after successful raise'
  );

  RETURN QUERY SELECT * FROM finish();
END;
$$;


--
-- TOC entry 1883 (class 1255 OID 25913)
-- Name: test_suite__sla_breach_detection(); Type: FUNCTION; Schema: complaints_test; Owner: -
--

CREATE FUNCTION complaints_test.test_suite__sla_breach_detection() RETURNS SETOF text
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_def text;
BEGIN
  SELECT pg_get_functiondef('public.check_complaint_sla_breaches()'::regprocedure)
  INTO v_def;

  RETURN QUERY SELECT plan(5);

  RETURN QUERY SELECT ok(
    position('SET response_breached = true' IN v_def) > 0,
    'SLA sweep marks response breaches'
  );

  RETURN QUERY SELECT ok(
    position('SET resolution_breached = true' IN v_def) > 0,
    'SLA sweep marks resolution breaches'
  );

  RETURN QUERY SELECT ok(
    position('is_escalated = true' IN v_def) > 0,
    'SLA sweep auto-escalates breached tickets'
  );

  RETURN QUERY SELECT ok(
    position('WHERE (response_breached = true OR resolution_breached = true)' IN v_def) > 0,
    'Auto-escalation condition is tied to breach flags'
  );

  RETURN QUERY SELECT ok(
    position('RETURNS TABLE(breached_count integer, escalated_count integer)' IN v_def) > 0,
    'SLA sweep exposes breach and escalation counters'
  );

  RETURN QUERY SELECT * FROM finish();
END;
$$;


--
-- TOC entry 667 (class 1255 OID 16551)
-- Name: grant_pg_cron_access(); Type: FUNCTION; Schema: extensions; Owner: -
--

CREATE FUNCTION extensions.grant_pg_cron_access() RETURNS event_trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF EXISTS (
    SELECT
    FROM pg_event_trigger_ddl_commands() AS ev
    JOIN pg_extension AS ext
    ON ev.objid = ext.oid
    WHERE ext.extname = 'pg_cron'
  )
  THEN
    grant usage on schema cron to postgres with grant option;

    alter default privileges in schema cron grant all on tables to postgres with grant option;
    alter default privileges in schema cron grant all on functions to postgres with grant option;
    alter default privileges in schema cron grant all on sequences to postgres with grant option;

    alter default privileges for user supabase_admin in schema cron grant all
        on sequences to postgres with grant option;
    alter default privileges for user supabase_admin in schema cron grant all
        on tables to postgres with grant option;
    alter default privileges for user supabase_admin in schema cron grant all
        on functions to postgres with grant option;

    grant all privileges on all tables in schema cron to postgres with grant option;
    revoke all on table cron.job from postgres;
    grant select on table cron.job to postgres with grant option;
  END IF;
END;
$$;


