-- TOC entry 614 (class 1255 OID 16391)
-- Name: get_auth(text); Type: FUNCTION; Schema: pgbouncer; Owner: -
--

CREATE FUNCTION pgbouncer.get_auth(p_usename text) RETURNS TABLE(username text, password text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $_$
  BEGIN
      RAISE DEBUG 'PgBouncer auth request: %', p_usename;

      RETURN QUERY
      SELECT
          rolname::text,
          CASE WHEN rolvaliduntil < now()
              THEN null
              ELSE rolpassword::text
          END
      FROM pg_authid
      WHERE rolname=$1 and rolcanlogin;
  END;
  $_$;


--
-- TOC entry 763 (class 1255 OID 22277)
-- Name: acknowledge(bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.acknowledge(p_complaint_id bigint) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_is_admin boolean := public.is_admin();
  v_dealer_code text := public.my_dealer_code();
BEGIN
  IF NOT (v_is_admin OR public.has_module_modify('complaints')) THEN
    RAISE EXCEPTION 'Insufficient permissions';
  END IF;

  IF v_is_admin THEN
    UPDATE public.complaint_tickets
    SET status = 'acknowledged'
    WHERE id = p_complaint_id;
  ELSE
    UPDATE public.complaint_tickets
    SET status = 'acknowledged'
    WHERE id = p_complaint_id
      AND dealer_code = v_dealer_code;
  END IF;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Complaint not found or not accessible';
  END IF;

  RETURN jsonb_build_object('status', 'acknowledged');
END;
$$;


--
-- TOC entry 760 (class 1255 OID 22274)
-- Name: add_customer_message(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.add_customer_message(p_token text, p_body text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_complaint_id bigint;
  v_customer_name text;
  v_dealer_code text;
BEGIN
  SELECT complaint_id INTO v_complaint_id
  FROM public.complaint_access_links
  WHERE token = p_token AND status = 'consumed';
  
  IF v_complaint_id IS NULL THEN
    RAISE EXCEPTION 'Invalid or inactive complaint link';
  END IF;
  
  -- Get customer name and dealer from the ticket
  SELECT customer_name, dealer_code INTO v_customer_name, v_dealer_code
  FROM public.complaint_tickets
  WHERE id = v_complaint_id;
  
  -- Add customer message (never is_internal)
  INSERT INTO public.complaint_messages (
    dealer_code, complaint_id, author_type, author_name, body, is_internal
  ) VALUES (
    v_dealer_code, v_complaint_id, 'customer', v_customer_name, p_body, false
  );
  
  -- Return updated view
  RETURN public.get_complaint_by_token(p_token);
END;
$$;


--
-- TOC entry 770 (class 1255 OID 22284)
-- Name: add_staff_message(bigint, text, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.add_staff_message(p_complaint_id bigint, p_body text, p_is_internal boolean DEFAULT false) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_dealer_code text;
  v_staff_name text;
BEGIN
  IF NOT (public.is_admin() OR public.has_module_modify('complaints')) THEN
    RAISE EXCEPTION 'Insufficient permissions';
  END IF;
  
  SELECT dealer_code INTO v_dealer_code
  FROM public.complaint_tickets
  WHERE id = p_complaint_id
    AND dealer_code = public.my_dealer_code();
  
  IF v_dealer_code IS NULL THEN
    RAISE EXCEPTION 'Complaint not found';
  END IF;
  
  SELECT full_name INTO v_staff_name FROM public.users WHERE id = auth.uid();
  
  INSERT INTO public.complaint_messages (
    dealer_code, complaint_id, author_type, author_id, author_name, body, is_internal
  ) VALUES (
    v_dealer_code, p_complaint_id, 'staff', auth.uid(), v_staff_name, p_body, p_is_internal
  );
  
  RETURN jsonb_build_object('message_added', true);
END;
$$;


--
-- TOC entry 737 (class 1255 OID 21028)
-- Name: apply_admin_bypass_policy_on_ddl(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_admin_bypass_policy_on_ddl() RETURNS event_trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_catalog'
    AS $$
DECLARE
  cmd RECORD;
  rel_name text;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
  LOOP
    IF cmd.object_type = 'table' AND cmd.schema_name IN ('public', 'storage') THEN
      SELECT c.relname INTO rel_name
      FROM pg_class c
      WHERE c.oid = cmd.objid;

      IF rel_name IS NOT NULL THEN
        PERFORM public.ensure_admin_bypass_policy(cmd.schema_name, rel_name);
      END IF;
    END IF;
  END LOOP;
END;
$$;


--
-- TOC entry 736 (class 1255 OID 21003)
-- Name: apply_admin_bypass_policy_to_existing_tables(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_admin_bypass_policy_to_existing_tables() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_catalog'
    AS $$
DECLARE
  t RECORD;
BEGIN
  FOR t IN
    SELECT n.nspname AS schema_name, c.relname AS table_name
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE c.relkind IN ('r', 'p')
      AND n.nspname IN ('public', 'storage')
      AND c.relrowsecurity = true
  LOOP
    PERFORM public.ensure_admin_bypass_policy(t.schema_name, t.table_name);
  END LOOP;
END;
$$;


--
-- TOC entry 1963 (class 1255 OID 33195)
-- Name: apply_dms_revenue_to_job_card_closed_row(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_dms_revenue_to_job_card_closed_row() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
  v_dms record;
begin
  if coalesce(btrim(NEW.job_card_number), '') = '' then
    NEW.dms_final_labour_amount := null;
    NEW.dms_total_invoice_amount := null;
    return NEW;
  end if;

  select *
    into v_dms
  from public.latest_psf_revenue_dms_for_job_card(
    NEW.job_card_number,
    NEW.location,
    NEW.portal
  );

  if found then
    NEW.dms_final_labour_amount := v_dms.final_labour_amount;
    NEW.dms_total_invoice_amount := v_dms.total_invoice_amount;
  else
    NEW.dms_final_labour_amount := null;
    NEW.dms_total_invoice_amount := null;
  end if;

  return NEW;
end;
$$;


--
-- TOC entry 751 (class 1255 OID 22020)
-- Name: apply_sa_business_mapping_on_employee_master(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_sa_business_mapping_on_employee_master() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  code_upper text;
BEGIN
  code_upper := upper(btrim(coalesce(NEW.employee_code, '')));

  IF code_upper = '' THEN
    RETURN NEW;
  END IF;

  IF code_upper LIKE '%500A840%' THEN
    NEW.location := 'Sitapura';
    NEW.fuel_type := 'EV';
  ELSIF code_upper LIKE '%3001440%' THEN
    NEW.location := 'Ajmer Road';
    NEW.fuel_type := 'PV';
  ELSIF code_upper LIKE '%3000840%' THEN
    NEW.location := 'Sitapura';
    NEW.fuel_type := 'PV';
  END IF;

  RETURN NEW;
END;
$$;


--
-- TOC entry 750 (class 1255 OID 22018)
-- Name: apply_sa_business_mapping_on_reception(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_sa_business_mapping_on_reception() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
  code_upper text;
  code_part1 text;
  code_part2 text;
  employee_location text;
  employee_fuel_type text;
  mapped_dealer_code text;
BEGIN
  code_upper := upper(btrim(coalesce(NEW.sa_employee_code, '')));
  code_part1 := upper(btrim(coalesce(split_part(NEW.sa_employee_code, '_', 1), '')));
  code_part2 := upper(btrim(coalesce(split_part(NEW.sa_employee_code, '_', 2), '')));

  IF code_upper = '' THEN
    RETURN NEW;
  END IF;

  SELECT
    NULLIF(btrim(em.location), ''),
    CASE WHEN upper(btrim(coalesce(em.fuel_type, ''))) IN ('EV', 'PV') THEN upper(btrim(em.fuel_type)) ELSE NULL END
  INTO employee_location, employee_fuel_type
  FROM public.employee_master em
  WHERE upper(btrim(coalesce(em.employee_code, ''))) IN (code_upper, code_part1, code_part2)
  ORDER BY
    CASE
      WHEN upper(btrim(coalesce(em.employee_code, ''))) = code_upper THEN 1
      WHEN upper(btrim(coalesce(em.employee_code, ''))) = code_part1 THEN 2
      WHEN upper(btrim(coalesce(em.employee_code, ''))) = code_part2 THEN 3
      ELSE 9
    END
  LIMIT 1;

  IF code_part1 IN ('3000840', '500A840', '3001440') THEN
    mapped_dealer_code := code_part1;
  ELSIF code_part2 IN ('3000840', '500A840', '3001440') THEN
    mapped_dealer_code := code_part2;
  ELSIF code_upper IN ('3000840', '500A840', '3001440') THEN
    mapped_dealer_code := code_upper;
  ELSE
    mapped_dealer_code := NULL;
  END IF;

  -- Preserve existing dealer_code mapping behavior.
  IF mapped_dealer_code IS NOT NULL THEN
    NEW.dealer_code := mapped_dealer_code;
  END IF;

  -- Winning source for location is employee_master.location, fallback to legacy mapping.
  NEW.branch := COALESCE(
    employee_location,
    NEW.branch,
    CASE mapped_dealer_code
      WHEN '500A840' THEN 'Sitapura'
      WHEN '3000840' THEN 'Sitapura'
      WHEN '3001440' THEN 'Ajmer Road'
      ELSE NULL
    END
  );

  NEW.location := COALESCE(
    employee_location,
    NULLIF(btrim(coalesce(NEW.location, '')), ''),
    NULLIF(btrim(regexp_replace(coalesce(NEW.branch, ''), '(?i)\s+(EV|PV)$', '')), ''),
    NULLIF(btrim(coalesce(NEW.branch, '')), '')
  );

  NEW.portal := COALESCE(
    employee_fuel_type,
    CASE mapped_dealer_code
      WHEN '500A840' THEN 'EV'
      WHEN '3000840' THEN 'PV'
      WHEN '3001440' THEN 'PV'
      ELSE NULL
    END,
    CASE
      WHEN upper(btrim(coalesce(NEW.branch, ''))) LIKE '% EV' THEN 'EV'
      WHEN upper(btrim(coalesce(NEW.branch, ''))) LIKE '% PV' THEN 'PV'
      ELSE NULL
    END,
    CASE WHEN upper(btrim(coalesce(NEW.portal, ''))) IN ('EV', 'PV') THEN upper(btrim(NEW.portal)) ELSE NULL END
  );

  NEW.branch_label := COALESCE(
    NULLIF(btrim(coalesce(NEW.branch, '')), ''),
    NEW.location
  );

  RETURN NEW;
END;
$_$;


