--
-- TOC entry 1966 (class 1255 OID 33211)
-- Name: backfill_job_card_closed_dms_revenue_batch(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.backfill_job_card_closed_dms_revenue_batch(p_batch_size integer DEFAULT 1000) RETURNS TABLE(processed_source_rows integer, updated_job_card_rows integer, last_psf_revenue_dms_id bigint, is_complete boolean)
    LANGUAGE plpgsql
    AS $$
declare
  v_start_after bigint := 0;
  v_last_id bigint := 0;
  v_processed integer := 0;
  v_updated integer := 0;
  v_total_updated integer := 0;
  v_batch_size integer := greatest(1, least(coalesce(p_batch_size, 1000), 10000));
  r record;
begin
  select p.last_psf_revenue_dms_id
    into v_start_after
  from public.psf_revenue_dms_backfill_progress p
  where p.id = true
  for update;

  for r in
    select d.id, d.job_card_number, d.location, d.portal
    from public.psf_revenue_dms d
    where d.id > v_start_after
      and coalesce(btrim(d.job_card_number), '') <> ''
    order by d.id
    limit v_batch_size
  loop
    v_processed := v_processed + 1;
    v_last_id := r.id;

    select public.refresh_job_card_closed_dms_revenue(r.job_card_number, r.location, r.portal)
      into v_updated;
    v_total_updated := v_total_updated + coalesce(v_updated, 0);
  end loop;

  update public.psf_revenue_dms_backfill_progress p
     set last_psf_revenue_dms_id = case when v_processed > 0 then v_last_id else p.last_psf_revenue_dms_id end,
         processed_source_rows = p.processed_source_rows + v_processed,
         updated_rows = p.updated_rows + v_total_updated,
         completed_at = case when v_processed = 0 then now() else null end,
         updated_at = now()
   where p.id = true;

  return query
  select
    v_processed,
    v_total_updated,
    case when v_processed > 0 then v_last_id else v_start_after end,
    v_processed = 0;
end;
$$;


--
-- TOC entry 1911 (class 1255 OID 27703)
-- Name: calc_all_service_assumed_next_service_date(text, text, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calc_all_service_assumed_next_service_date(p_last_service_date text, p_last_service_type text, p_as_of_date date DEFAULT CURRENT_DATE) RETURNS date
    LANGUAGE sql STABLE
    AS $$
  WITH parsed AS (
    SELECT public.parse_all_service_date_text(p_last_service_date) AS last_service_dt
  ), normalized AS (
    SELECT lower(btrim(COALESCE(p_last_service_type, ''))) AS lst
  ), inferred_type AS (
    SELECT public.calc_all_service_assumed_next_service_type(p_last_service_type) AS assumed_type
  )
  SELECT
    CASE
      WHEN it.assumed_type = 'Unknown' THEN NULL
      WHEN p.last_service_dt IS NULL THEN NULL
      ELSE p_as_of_date + (
        (
          CASE
            WHEN n.lst = '' OR n.lst = 'new' THEN 60
            WHEN n.lst IN ('first free service', 'tma-first free service') THEN 120
            ELSE 180
          END
        )
        - MOD(GREATEST(0, (p_as_of_date - p.last_service_dt)::int), 180)
      )
    END
  FROM parsed p
  CROSS JOIN normalized n
  CROSS JOIN inferred_type it;
$$;


