--

COMMENT ON FUNCTION public.calc_all_service_assumed_next_service_date(p_last_service_date text, p_last_service_type text, p_as_of_date date) IS 'Implements approved Phase 4 rule: assumed_next_service_date = as_of_date + (target_days - MOD(GREATEST(0, as_of_date - parsed_last_service_date), 180)); target_days: 60 for new/null/empty, 120 for first free/tma-first free, else 180. Additional guard: returns NULL when inferred assumed_next_service_type is Unknown.';


