--

COMMENT ON FUNCTION public.calc_all_service_dynamic_priority_score(p_assumed_next_service_date date, p_assumed_next_service_type text, p_vehicle_sale_date_text text) IS 'Higher score = higher priority inside bucket. Encodes assumed_next_service_date asc (NULL last), then assumed_next_service_type rank, then exact vehicle_sale_date desc (new to old; NULL/unparseable last).';


--
-- TOC entry 1914 (class 1255 OID 27721)
-- Name: calc_all_service_powertrain_type(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calc_all_service_powertrain_type(p_product_line text) RETURNS text
    LANGUAGE sql STABLE
    AS $_$
  WITH normalized AS (
    SELECT upper(btrim(COALESCE(p_product_line, ''))) AS pl
  ), base AS (
    SELECT
      CASE
        WHEN n.pl = '' THEN NULL
        WHEN n.pl LIKE '%EV%' THEN 'EV'
        WHEN n.pl LIKE '%CNG%' THEN 'CNG'
        WHEN (
          n.pl ~ '(^|[^A-Z0-9])QJET([^A-Z0-9]|$)'
          OR n.pl LIKE '%DICOR%'
          OR n.pl ~ '(^|[^A-Z0-9])CR4([^A-Z0-9]|$)'
          OR n.pl LIKE '%(D)%'
          OR n.pl LIKE '%DIESEL%'
          OR n.pl LIKE '%1.05 D%'
          OR n.pl ~ '(^|[^0-9])1\.5([^0-9]|$)'
        ) THEN 'DIESEL'
        WHEN (
          n.pl LIKE '%(P)%'
          OR n.pl LIKE '%PETROL%'
          OR n.pl LIKE '%1.2 P%'
          OR n.pl LIKE '%1.0 P%'
          OR n.pl LIKE '%GDI%'
        ) THEN 'PETROL'
        ELSE NULL
      END AS base_result,
      n.pl
    FROM normalized n
  ), ov AS (
    SELECT o.powertrain_type
    FROM base b
    JOIN public.all_service_data_powertrain_overrides o
      ON o.is_active = true
     AND b.pl LIKE upper(o.match_pattern)
    ORDER BY o.priority ASC, o.id ASC
    LIMIT 1
  )
  SELECT
    CASE
      WHEN b.base_result IS NOT NULL THEN b.base_result
      WHEN EXISTS (SELECT 1 FROM ov) THEN (SELECT powertrain_type FROM ov)
      WHEN b.pl = '' THEN NULL
      ELSE 'UNKNOWN'
    END
  FROM base b;
$_$;


