-- Name: FUNCTION calc_all_service_powertrain_type(p_product_line text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.calc_all_service_powertrain_type(p_product_line text) IS 'Deterministic powertrain mapping from product_line. Ordered rules: EV/CNG/DIESEL/PETROL explicit markers, then active override table match_pattern by priority, else UNKNOWN; blank => NULL.';


--
-- TOC entry 1897 (class 1255 OID 26962)
-- Name: can_access_bodyshop_surveyor_settings(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_access_bodyshop_surveyor_settings(target_dealer text) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_target text := UPPER(BTRIM(COALESCE(target_dealer, '')));
  v_has_bodyshop_role boolean := false;
  v_has_module_access boolean := false;
BEGIN
  IF v_uid IS NULL OR v_target = '' THEN
    RETURN false;
  END IF;

  IF public.is_admin() THEN
    RETURN true;
  END IF;

  SELECT EXISTS (
    SELECT 1
    FROM public.get_my_bodyshop_employee_scope() s
    WHERE UPPER(BTRIM(COALESCE(s.role, ''))) IN ('SA', 'EDP', 'SURVEY')
  ) INTO v_has_bodyshop_role;

  v_has_module_access := (
    public.has_module_view('settings'::text)
    OR public.has_module_view('bodyshop_repair'::text)
    OR public.has_module_modify('bodyshop_repair'::text)
  );

  RETURN (
    EXISTS (
      SELECT 1
      FROM unnest(public.my_effective_dealer_codes()) AS dc(code)
      WHERE UPPER(BTRIM(COALESCE(dc.code, ''))) = v_target
    )
    OR EXISTS (
      SELECT 1
      FROM public.user_employee_links uel
      WHERE uel.user_id = v_uid
        AND uel.is_active = true
        AND UPPER(BTRIM(COALESCE(uel.dealer_code, ''))) = v_target
    )
  )
  AND (v_has_module_access OR v_has_bodyshop_role);
END;
$$;


