--
-- TOC entry 796 (class 1255 OID 23259)
-- Name: capture_bodyshop_customer_group_wa_click(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.capture_bodyshop_customer_group_wa_click() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- First transition from stage <=4 to stage >=5 marks Customer Group completion.
  IF COALESCE(OLD.current_stage, 0) <= 4 AND COALESCE(NEW.current_stage, 0) >= 5 THEN
    IF NEW.customer_group_wa_sent_at IS NULL THEN
      NEW.customer_group_wa_sent_at := COALESCE(NEW.updated_at, now());
    END IF;

    IF COALESCE(BTRIM(NEW.customer_group_wa_sent_by), '') = '' THEN
      NEW.customer_group_wa_sent_by := COALESCE(auth.uid()::text, NEW.customer_group_wa_sent_by);
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


--
-- TOC entry 772 (class 1255 OID 22286)
-- Name: check_complaint_sla_breaches(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_complaint_sla_breaches() RETURNS TABLE(breached_count integer, escalated_count integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_breached_count integer := 0;
  v_escalated_count integer := 0;
BEGIN
  -- Mark response breaches
  UPDATE public.complaint_tickets
  SET response_breached = true
  WHERE response_due_at < now()
    AND first_response_at IS NULL
    AND response_breached = false
    AND status IN ('new', 'acknowledged');
  
  GET DIAGNOSTICS v_breached_count = ROW_COUNT;
  
  -- Mark resolution breaches
  UPDATE public.complaint_tickets
  SET resolution_breached = true
  WHERE resolution_due_at < now()
    AND status NOT IN ('resolved', 'closed')
    AND resolution_breached = false;
  
  GET DIAGNOSTICS v_escalated_count = ROW_COUNT;
  
  -- Auto-escalate breached tickets
  UPDATE public.complaint_tickets
  SET
    is_escalated = true,
    escalated_at = now(),
    escalation_reason = 'SLA breached: auto-escalated'
  WHERE (response_breached = true OR resolution_breached = true)
    AND is_escalated = false;
  
  RETURN QUERY SELECT v_breached_count::integer, v_escalated_count::integer;
END;
$$;


--
-- TOC entry 766 (class 1255 OID 22280)
-- Name: close(bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.close(p_complaint_id bigint) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_is_admin boolean := public.is_admin();
  v_dealer_code text := public.my_dealer_code();
BEGIN
  IF NOT (v_is_admin OR public.has_module_modify('complaints')) THEN
    RAISE EXCEPTION 'Insufficient permissions';
  END IF;

  IF v_is_admin THEN
    UPDATE public.complaint_tickets
    SET status = 'closed'
    WHERE id = p_complaint_id;
  ELSE
    UPDATE public.complaint_tickets
    SET status = 'closed'
    WHERE id = p_complaint_id
      AND dealer_code = v_dealer_code;
  END IF;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Complaint not found or not accessible';
  END IF;

  RETURN jsonb_build_object('status', 'closed');
END;
$$;


--
-- TOC entry 709 (class 1255 OID 17903)
-- Name: compute_parts_order_status(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.compute_parts_order_status() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  new.order_status := case
    when coalesce(new.received_quantity, 0) >= coalesce(new.ordered_quantity, 0)
      and coalesce(new.ordered_quantity, 0) > 0 then 'Received'
    when coalesce(new.intransit_qty, 0) > 0 or coalesce(new.challan_qty, 0) > 0 then 'In-Transit'
    when coalesce(new.invoice_qty, 0) > 0 then 'Invoiced'
    when coalesce(new.confirmation_qty, 0) > 0 then 'Confirmed'
    when new.order_date is not null then 'Ordered'
    else null
  end;
  return new;
end;
$$;


