    UPDATE auth.users
    SET email_confirmed_at = COALESCE(email_confirmed_at, NOW()), updated_at = NOW()
    WHERE id = NEW.id AND email_confirmed_at IS NULL;
  END IF;
  RETURN NEW;
END;
$$;


