--

CREATE FUNCTION public.enforce_bodyshop_stage_pointer_s9_guard() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
	v_survey_status text;
	v_survey_hold_reason text;
	v_floor_assigned boolean;
	v_stage9_done boolean;
BEGIN
	IF COALESCE(NEW.overall_status, 'active') <> 'active' THEN
		RETURN NEW;
	END IF;

	v_survey_status := lower(btrim(COALESCE(NEW.survey_status, '')));
	v_survey_hold_reason := btrim(COALESCE(NEW.survey_hold_reason, ''));
	v_floor_assigned := lower(btrim(COALESCE(NEW.bodyshop_floor, ''))) IN ('floor 2', 'floor 3');

	v_stage9_done := (
		NEW.survey_date IS NOT NULL
		AND (v_survey_status IN ('hold', 'approved'))
		AND (v_survey_status <> 'hold' OR v_survey_hold_reason <> '')
		AND v_floor_assigned
	);

	IF COALESCE(NEW.current_stage, 1) > 9 AND NOT v_stage9_done THEN
		NEW.current_stage := 9;
		NEW.current_stage_name := 'Survey';
	END IF;

	RETURN NEW;
END;
$$;


--
-- TOC entry 723 (class 1255 OID 20456)
-- Name: enforce_service_reception_sa_update(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enforce_service_reception_sa_update() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF public.is_admin() OR public.has_module_view('reception') THEN
    RETURN NEW;
  END IF;

  IF public.has_module_modify('service_advisor') THEN
    -- Ownership gate: SA can only update rows mapped to their employee code(s).
    IF OLD.sa_employee_code IS NULL OR NOT public.user_has_employee_code(OLD.sa_employee_code) THEN
      RAISE EXCEPTION 'You can update only your own assigned rows | code: P0001';
    END IF;

    -- SA may edit only these fields: service_type, jc_number, remark, estimate_* and updated_at.
    IF NEW.dealer_code IS DISTINCT FROM OLD.dealer_code
      OR NEW.reg_number IS DISTINCT FROM OLD.reg_number
      OR NEW.model IS DISTINCT FROM OLD.model
      OR NEW.sa_name IS DISTINCT FROM OLD.sa_name
      OR NEW.sa_employee_code IS DISTINCT FROM OLD.sa_employee_code
      OR NEW.sa_display_name IS DISTINCT FROM OLD.sa_display_name
      OR NEW.owner_name IS DISTINCT FROM OLD.owner_name
      OR NEW.owner_phone IS DISTINCT FROM OLD.owner_phone
      OR NEW.source IS DISTINCT FROM OLD.source
      OR NEW.created_by IS DISTINCT FROM OLD.created_by
      OR NEW.created_at IS DISTINCT FROM OLD.created_at THEN
      RAISE EXCEPTION 'Service Advisor can edit only Service Type, Job Card Number, Remark, and Estimate fields';
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


--
-- TOC entry 1935 (class 1255 OID 29246)
-- Name: enqueue_all_service_history_sync(text, interval); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enqueue_all_service_history_sync(p_chassis_no text, p_delay interval DEFAULT '00:00:45'::interval) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_key text;
  v_delay interval;
BEGIN
  v_key := nullif(upper(btrim(coalesce(p_chassis_no, ''))), '');
  v_delay := COALESCE(p_delay, interval '45 seconds');

  IF v_key IS NULL THEN
    RETURN;
  END IF;

  INSERT INTO public.all_service_history_sync_queue (
    chassis_key,
    last_event_at,
    not_before,
    enqueue_count,
    source_tag
  )
  VALUES (
    v_key,
    now(),
    now() + v_delay,
    1,
    'trigger'
  )
  ON CONFLICT (chassis_key) DO UPDATE
  SET
    last_event_at = EXCLUDED.last_event_at,
    not_before = GREATEST(public.all_service_history_sync_queue.not_before, EXCLUDED.not_before),
    enqueue_count = public.all_service_history_sync_queue.enqueue_count + 1,
    source_tag = EXCLUDED.source_tag;
END;
$$;


