--
-- TOC entry 1952 (class 1255 OID 30771)
-- Name: enqueue_psf_import_run(text, text, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enqueue_psf_import_run(p_branch_slot text, p_source_file_name text, p_rows jsonb) RETURNS TABLE(import_run_id bigint, status text, total_rows integer, staged_rows integer, error_message text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_run_id bigint;
  v_total_rows integer := 0;
  v_staged_rows integer := 0;
begin
  v_total_rows := coalesce(jsonb_array_length(coalesce(p_rows, '[]'::jsonb)), 0);

  insert into public.psf_import_runs (
    status,
    branch_slot,
    source_file_name,
    total_rows,
    started_at,
    completed_at,
    error_message
  )
  values (
    'queued',
    p_branch_slot,
    p_source_file_name,
    v_total_rows,
    null,
    null,
    null
  )
  returning id into v_run_id;

  if v_total_rows > 0 then
    insert into public.psf_import_staging (
      import_run_id,
      row_number,
      branch,
      branch_label,
      location,
      portal,
      invoice_date,
      job_card_number,
      sr_type,
      chassis_number,
      final_labour_amount,
      final_spares_amount,
      total_invoice_amount,
      parent_product_line,
      product_line,
      created_date_time,
      closed_date_time,
      first_name,
      last_name,
      sr_assigned_to,
      employee_code,
      vehicle_registration_number,
      vehicle_sale_date,
      account_phone_number,
      lubs_revenue,
      kms_run,
      last_service_km,
      last_service_date,
      source_row
    )
    select
      v_run_id,
      src.ordinality::integer,
      nullif(btrim(src.row ->> 'branch'), ''),
      nullif(btrim(src.row ->> 'branch_label'), ''),
      nullif(btrim(src.row ->> 'location'), ''),
      public.psf_normalize_portal(src.row ->> 'portal'),
      public.psf_try_date(src.row ->> 'invoice_date'),
      nullif(upper(btrim(src.row ->> 'job_card_number')), ''),
      nullif(btrim(src.row ->> 'sr_type'), ''),
      nullif(upper(btrim(src.row ->> 'chassis_number')), ''),
      public.psf_try_numeric(src.row ->> 'final_labour_amount'),
      public.psf_try_numeric(src.row ->> 'final_spares_amount'),
      public.psf_try_numeric(src.row ->> 'total_invoice_amount'),
      nullif(btrim(src.row ->> 'parent_product_line'), ''),
      nullif(btrim(src.row ->> 'product_line'), ''),
      public.psf_try_timestamptz(src.row ->> 'created_date_time'),
      public.psf_try_timestamptz(src.row ->> 'closed_date_time'),
      nullif(btrim(src.row ->> 'first_name'), ''),
      nullif(btrim(src.row ->> 'last_name'), ''),
      nullif(btrim(src.row ->> 'sr_assigned_to'), ''),
      nullif(upper(btrim(src.row ->> 'employee_code')), ''),
      nullif(upper(btrim(src.row ->> 'vehicle_registration_number')), ''),
      public.psf_try_date(src.row ->> 'vehicle_sale_date'),
      nullif(btrim(src.row ->> 'account_phone_number'), ''),
      public.psf_try_numeric(src.row ->> 'lubs_revenue'),
      public.psf_try_numeric(src.row ->> 'kms_run'),
      public.psf_try_numeric(src.row ->> 'last_service_km'),
      public.psf_try_date(src.row ->> 'last_service_date'),
      src.row
    from jsonb_array_elements(coalesce(p_rows, '[]'::jsonb)) with ordinality as src(row, ordinality);
  end if;

  select count(*) into v_staged_rows
  from public.psf_import_staging s
  where s.import_run_id = v_run_id;

  update public.psf_import_runs
  set staged_rows = v_staged_rows
  where id = v_run_id;

  return query
  select
    v_run_id,
    'queued'::text,
    v_total_rows,
    v_staged_rows,
    null::text;
exception
  when others then
    if v_run_id is not null then
      update public.psf_import_runs
      set
        status = 'failed',
        error_message = sqlerrm,
        completed_at = now()
      where id = v_run_id;
    end if;

    return query
    select
      coalesce(v_run_id, 0),
      'failed'::text,
      coalesce(v_total_rows, 0),
      coalesce(v_staged_rows, 0),
      sqlerrm;
end;
$$;


--
-- TOC entry 735 (class 1255 OID 21002)
-- Name: ensure_admin_bypass_policy(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ensure_admin_bypass_policy(target_schema text, target_table text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_catalog'
    AS $$
DECLARE
  fq_table text;
  has_rls boolean;
  owner_name text;
BEGIN
  IF target_schema IS NULL OR target_table IS NULL THEN
    RETURN;
  END IF;

  -- Restrict automation to app tables only.
  IF target_schema NOT IN ('public', 'storage') THEN
    RETURN;
  END IF;

  fq_table := format('%I.%I', target_schema, target_table);

  SELECT c.relrowsecurity, pg_get_userbyid(c.relowner)
  INTO has_rls, owner_name
  FROM pg_class c
  JOIN pg_namespace n ON n.oid = c.relnamespace
  WHERE n.nspname = target_schema
    AND c.relname = target_table
    AND c.relkind IN ('r', 'p');

  -- Do not alter baseline behavior for tables that are not already RLS-protected.
  IF COALESCE(has_rls, false) = false THEN
    RETURN;
  END IF;

  -- CREATE POLICY requires table ownership; skip tables owned by managed platform roles.
  IF owner_name IS DISTINCT FROM current_user THEN
    RAISE NOTICE 'Skipping %.%: owner is %, executor is %', target_schema, target_table, owner_name, current_user;
    RETURN;
  END IF;

  BEGIN
    EXECUTE format(
      'DROP POLICY IF EXISTS admin_unrestricted_all_ops_v1 ON %s',
      fq_table
    );

    EXECUTE format(
      'CREATE POLICY admin_unrestricted_all_ops_v1 ON %s FOR ALL TO authenticated USING (public.is_admin()) WITH CHECK (public.is_admin())',
      fq_table
    );
  EXCEPTION
    WHEN insufficient_privilege THEN
      RAISE NOTICE 'Skipping %.% due to insufficient privilege while creating policy', target_schema, target_table;
      RETURN;
  END;
END;
$$;


--
-- TOC entry 769 (class 1255 OID 22283)
-- Name: escalate(bigint, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.escalate(p_complaint_id bigint, p_escalation_reason text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_is_admin boolean := public.is_admin();
  v_dealer_code text := public.my_dealer_code();
BEGIN
  IF NOT (v_is_admin OR public.has_module_modify('complaints')) THEN
    RAISE EXCEPTION 'Insufficient permissions';
  END IF;

  IF v_is_admin THEN
    UPDATE public.complaint_tickets
    SET
      is_escalated = true,
      escalated_at = now(),
      escalation_reason = p_escalation_reason
    WHERE id = p_complaint_id;
  ELSE
    UPDATE public.complaint_tickets
    SET
      is_escalated = true,
      escalated_at = now(),
      escalation_reason = p_escalation_reason
    WHERE id = p_complaint_id
      AND dealer_code = v_dealer_code;
  END IF;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Complaint not found or not accessible';
  END IF;

  RETURN jsonb_build_object('is_escalated', true);
END;
$$;


--
-- TOC entry 771 (class 1255 OID 22285)
-- Name: generate_complaint_link(bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_complaint_link(p_reception_entry_id bigint) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_dealer_code text;
  v_token text;
  v_link_id bigint;
  v_sa_employee_code text;
BEGIN
  SELECT dealer_code, sa_employee_code
    INTO v_dealer_code, v_sa_employee_code
  FROM public.service_reception_entries
  WHERE id = p_reception_entry_id;

  IF v_dealer_code IS NULL THEN
    RAISE EXCEPTION 'Reception entry not found';
  END IF;

  IF NOT (
    public.is_admin()
    OR public.has_module_modify('complaints')
    OR (
      public.has_module_modify('service_advisor')
      AND v_sa_employee_code IS NOT NULL
      AND (
        public.user_has_employee_code(v_sa_employee_code)
        OR public.user_is_crm_for_dealer_sa(v_sa_employee_code)
        OR EXISTS (
          SELECT 1
          FROM public.user_employee_links uel
          JOIN public.employee_master em
            ON em.employee_code = uel.employee_code
          WHERE uel.user_id = auth.uid()
            AND uel.is_active = true
            AND lower(btrim(coalesce(em.role, ''))) = ANY (ARRAY['sm', 'gm'])
        )
      )
    )
  ) THEN
    RAISE EXCEPTION 'Insufficient permissions';
  END IF;

  -- Generate a 128-bit random token (URL-safe base64)
  v_token := encode(gen_random_bytes(16), 'base64')
    || encode(gen_random_bytes(8), 'base64');

  -- Remove padding and special chars
  v_token := REPLACE(REPLACE(REPLACE(v_token, '/', '_'), '+', '-'), '=', '');
  v_token := SUBSTRING(v_token FROM 1 FOR 24);

  -- One active link per reception entry
  INSERT INTO public.complaint_access_links (
    dealer_code, reception_entry_id, token, status
  ) VALUES (
    v_dealer_code, p_reception_entry_id, v_token, 'active'
  )
  ON CONFLICT (reception_entry_id) DO UPDATE
  SET token = v_token, status = 'active', created_at = now()
  RETURNING id INTO v_link_id;

  RETURN jsonb_build_object(
    'link_id', v_link_id,
    'token', v_token,
    'url', 'https://tw.care/c/' || v_token
  );
END;
$$;


--
-- TOC entry 799 (class 1255 OID 23924)
-- Name: generate_lead_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_lead_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
declare
  date_part text;
  seq_num   int;
begin
  if new.lead_number is null or new.lead_number = '' then
    date_part := to_char(current_date, 'YYYYMMDD');
    select coalesce(max(
      case when lead_number ~ ('^BKG-' || date_part || '-[0-9]+$')
           then (split_part(lead_number, '-', 3))::int else 0 end
    ), 0) + 1
    into seq_num
    from public.service_bookings;
    new.lead_number := 'BKG-' || date_part || '-' || lpad(seq_num::text, 4, '0');
  end if;
  return new;
end;
$_$;


