--
-- TOC entry 1939 (class 1255 OID 29846)
-- Name: get_permissions_for_user(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_permissions_for_user(target_user_id uuid) RETURNS TABLE(module_name text, module_label text, module_route text, can_view boolean, can_modify boolean, can_delete boolean)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  -- Only admin users may call this
  SELECT m.name, m.label, m.route, p.can_view, p.can_modify, p.can_delete
  FROM public.user_module_permissions p
  JOIN public.modules m ON m.id = p.module_id
  WHERE p.user_id = target_user_id
    AND m.is_active = true
    AND p.can_view = true
  ORDER BY m.sort_order;
$$;


--
-- TOC entry 746 (class 1255 OID 21937)
-- Name: get_reception_by_jc_case_insensitive(text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_reception_by_jc_case_insensitive(p_jc_numbers text[]) RETURNS TABLE(jc_number text, reg_number text)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    s.jc_number,
    s.reg_number
  FROM public.service_reception_entries s
  WHERE UPPER(BTRIM(COALESCE(s.jc_number, ''))) = ANY(
    SELECT UPPER(BTRIM(v)) FROM UNNEST(p_jc_numbers) AS t(v)
  );
END;
$$;


--
-- TOC entry 745 (class 1255 OID 21936)
-- Name: get_revenue_by_jc_case_insensitive(text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_revenue_by_jc_case_insensitive(p_jc_numbers text[]) RETURNS TABLE(job_card_number text, closed_date_time timestamp without time zone, invoice_date timestamp without time zone, final_labour_amount numeric)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    j.job_card_number,
    j.closed_date_time,
    j.invoice_date,
    j.final_labour_amount
  FROM public.job_card_closed_data j
  WHERE UPPER(BTRIM(COALESCE(j.job_card_number, ''))) = ANY(
    SELECT UPPER(BTRIM(v)) FROM UNNEST(p_jc_numbers) AS t(v)
  );
END;
$$;


--
-- TOC entry 1888 (class 1255 OID 26091)
-- Name: get_unread_complaint_notification_count(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_unread_complaint_notification_count() RETURNS integer
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT COUNT(*)::integer
  FROM public.complaint_notifications n
  WHERE n.channel = 'in_app'
    AND n.read_at IS NULL
    AND n.dismissed_at IS NULL
    AND (
      n.recipient_user_id = auth.uid()
      OR (
        public.is_admin()
        AND n.recipient_user_id IS NULL
        AND public.dealer_code_in_scope(n.dealer_code)
      )
    );
$$;


--
-- TOC entry 726 (class 1255 OID 20598)
-- Name: grant_active_module_to_admins(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.grant_active_module_to_admins() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NEW.is_active = true THEN
    INSERT INTO public.user_module_permissions (
      user_id,
      module_id,
      can_view,
      can_modify,
      can_delete,
      granted_by,
      granted_at
    )
    SELECT
      u.id,
      NEW.id,
      true,
      true,
      true,
      NULL::uuid,
      now()
    FROM public.users u
    WHERE u.role = 'admin'
      AND u.is_active = true
    ON CONFLICT (user_id, module_id)
    DO UPDATE SET
      can_view = true,
      can_modify = true,
      can_delete = true,
      granted_at = now();
  END IF;

  RETURN NEW;
END;
$$;


--
-- TOC entry 727 (class 1255 OID 20601)
