--

CREATE FUNCTION public.grant_admin_all_active_modules() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NEW.role = 'admin' AND NEW.is_active = true THEN
    INSERT INTO public.user_module_permissions (
      user_id,
      module_id,
      can_view,
      can_modify,
      can_delete,
      granted_by,
      granted_at
    )
    SELECT
      NEW.id,
      m.id,
      true,
      true,
      true,
      NULL::uuid,
      now()
    FROM public.modules m
    WHERE m.is_active = true
    ON CONFLICT (user_id, module_id)
    DO UPDATE SET
      can_view = true,
      can_modify = true,
      can_delete = true,
      granted_at = now();
  END IF;

  RETURN NEW;
END;
$$;


--
-- TOC entry 713 (class 1255 OID 18602)
-- Name: handle_new_user(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.handle_new_user() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  INSERT INTO public.users (id, email, full_name)
  VALUES (
    NEW.id,
    NEW.email,
    COALESCE(NEW.raw_user_meta_data->>'full_name', NEW.email)
  )
  ON CONFLICT (id) DO NOTHING;
  RETURN NEW;
END;
$$;


--
-- TOC entry 725 (class 1255 OID 20575)
-- Name: has_module_action(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.has_module_action(p_module text, p_action text) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT CASE LOWER(p_action)
    WHEN 'view' THEN public.has_module_view(p_module)
    WHEN 'modify' THEN public.has_module_modify(p_module)
    WHEN 'delete' THEN public.has_module_delete(p_module)
    ELSE false
  END;
$$;


