--
-- TOC entry 1908 (class 1255 OID 27453)
-- Name: is_all_service_dynamic_match(public.all_service_data); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_all_service_dynamic_match(r public.all_service_data) RETURNS boolean
    LANGUAGE sql STABLE
    AS $$
  SELECT
    (
      r.chassis_no IS NOT NULL
      AND COALESCE(
        (
          SELECT bool_and(e.value IS NULL)
          FROM jsonb_each(
            to_jsonb(r) - ARRAY['id','chassis_no','created_at','last_updated_at']
          ) AS e(key, value)
        ),
        true
      )
    )
    OR
    (
      r.chassis_no IS NOT NULL
      AND r.assumed_next_service_date = (current_date + 2)
    )
    OR
    (
      r.chassis_no IS NOT NULL
      AND (
        NULLIF(btrim(r.last_service_type), '') IS NULL
        OR btrim(r.last_service_type) !~* 'service'
      )
    )
    OR
    (
      r.chassis_no IS NOT NULL
      AND COALESCE(
        NULLIF(lower(btrim(r.updated_by_robot::text)), ''),
        'false'
      ) IN ('false', 'f')
    );
$$;


--
-- TOC entry 8791 (class 0 OID 0)
-- Dependencies: 1908
-- Name: FUNCTION is_all_service_dynamic_match(r public.all_service_data); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.is_all_service_dynamic_match(r public.all_service_data) IS 'Active include conditions: (1) chassis_no present and all non-technical columns are NULL OR (2) assumed_next_service_date = current_date + 2 OR (3) last_service_type is NULL/blank or does not contain Service text OR (4) updated_by_robot is NULL/blank/false.';


--
-- TOC entry 1891 (class 1255 OID 26270)
-- Name: is_income_assignment_eligible(text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_income_assignment_eligible(p_module_key text, p_assignment_source text, p_employee_code text) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.employee_master em
    JOIN public.income_role_scope rs
      ON rs.is_active = true
     AND upper(btrim(rs.module_key)) = upper(btrim(coalesce(p_module_key, '')))
     AND upper(btrim(rs.assignment_source)) = upper(btrim(coalesce(p_assignment_source, '')))
     AND upper(btrim(rs.employee_role)) = upper(btrim(coalesce(em.role, '')))
    WHERE upper(btrim(coalesce(em.employee_code, ''))) = upper(btrim(coalesce(p_employee_code, '')))
  );
$$;


