-- Name: latest_psf_revenue_dms_for_job_card(text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.latest_psf_revenue_dms_for_job_card(p_job_card_number text, p_location text DEFAULT NULL::text, p_portal text DEFAULT NULL::text) RETURNS TABLE(final_labour_amount numeric, total_invoice_amount numeric)
    LANGUAGE sql STABLE
    AS $$
  select
    d.final_labour_amount,
    d.total_invoice_amount
  from public.psf_revenue_dms d
  where upper(btrim(d.job_card_number)) = upper(btrim(p_job_card_number))
    and coalesce(btrim(d.job_card_number), '') <> ''
    and (
      coalesce(btrim(p_location), '') = ''
      or d.location = p_location
    )
    and (
      coalesce(btrim(p_portal), '') = ''
      or d.portal = p_portal
    )
  order by d.invoice_date desc nulls last, d.id desc
  limit 1
$$;


--
-- TOC entry 1887 (class 1255 OID 26090)
-- Name: list_my_complaint_notifications(integer, integer, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.list_my_complaint_notifications(p_limit integer DEFAULT 20, p_offset integer DEFAULT 0, p_include_dismissed boolean DEFAULT false) RETURNS TABLE(id bigint, complaint_id bigint, event_type text, recipient_type text, channel text, status text, payload jsonb, created_at timestamp with time zone, seen_at timestamp with time zone, read_at timestamp with time zone, dismissed_at timestamp with time zone)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT
    n.id,
    n.complaint_id,
    n.event_type,
    n.recipient_type,
    n.channel,
    n.status,
    n.payload,
    n.created_at,
    n.seen_at,
    n.read_at,
    n.dismissed_at
  FROM public.complaint_notifications n
  WHERE n.channel = 'in_app'
    AND (p_include_dismissed OR n.dismissed_at IS NULL)
    AND (
      n.recipient_user_id = auth.uid()
      OR (
        public.is_admin()
        AND n.recipient_user_id IS NULL
        AND public.dealer_code_in_scope(n.dealer_code)
      )
    )
  ORDER BY n.created_at DESC
  LIMIT LEAST(GREATEST(COALESCE(p_limit, 20), 1), 100)
  OFFSET GREATEST(COALESCE(p_offset, 0), 0);
$$;


--
