--
-- TOC entry 1899 (class 1255 OID 27068)
-- Name: normalize_employee_master_department(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.normalize_employee_master_department() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  normalized_no_space text;
BEGIN
  NEW.department := NULLIF(BTRIM(COALESCE(NEW.department, '')), '');

  IF NEW.department IS NULL THEN
    RETURN NEW;
  END IF;

  normalized_no_space := UPPER(REPLACE(NEW.department, ' ', ''));
  IF normalized_no_space = 'BODYSHOP' THEN
    NEW.department := 'BODY SHOP';
  END IF;

  RETURN NEW;
END;
$$;


