--
-- TOC entry 773 (class 1255 OID 22379)
-- Name: normalize_job_card_support_assignment(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.normalize_job_card_support_assignment() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.job_card_number := upper(btrim(coalesce(NEW.job_card_number, '')));
  NEW.support_role := upper(btrim(coalesce(NEW.support_role, '')));
  NEW.employee_code := upper(btrim(coalesce(NEW.employee_code, '')));
  NEW.employee_name := btrim(coalesce(NEW.employee_name, ''));

  IF NEW.job_card_number = '' THEN
    RAISE EXCEPTION 'job_card_number is required';
  END IF;

  IF NEW.employee_code = '' THEN
    RAISE EXCEPTION 'employee_code is required';
  END IF;

  IF NEW.employee_name = '' THEN
    RAISE EXCEPTION 'employee_name is required';
  END IF;

  RETURN NEW;
END;
$$;


--
-- TOC entry 732 (class 1255 OID 20940)
-- Name: normalize_parts_consumption_sum(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.normalize_parts_consumption_sum() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.otc_quantity := COALESCE(NEW.otc_quantity, 0);
  NEW.ws_quantity := COALESCE(NEW.ws_quantity, 0);

  -- if only total is provided, map to OTC
  IF NEW.otc_quantity = 0 AND NEW.ws_quantity = 0 AND COALESCE(NEW.total_consumption, 0) > 0 THEN
    NEW.otc_quantity := NEW.total_consumption;
  END IF;

  NEW.quantity_consumed := NEW.otc_quantity + NEW.ws_quantity;
  NEW.total_consumption := NEW.otc_quantity + NEW.ws_quantity;
  RETURN NEW;
END;
$$;


--
-- TOC entry 797 (class 1255 OID 23719)
-- Name: normalize_technician_assignment_job_card_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.normalize_technician_assignment_job_card_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
declare
  reception_id_text text;
  mapped_jc text;
begin
  if NEW.job_card_number is not null then
    NEW.job_card_number := upper(btrim(NEW.job_card_number));
  end if;

  if NEW.job_card_number is null or NEW.job_card_number = '' then
    return NEW;
  end if;

  reception_id_text := substring(NEW.job_card_number from '^RECEPTION-([0-9]+)$');
  if reception_id_text is null then
    return NEW;
  end if;

  select upper(btrim(jc_number))
    into mapped_jc
  from public.service_reception_entries
  where id = reception_id_text::bigint
    and nullif(btrim(jc_number), '') is not null
  limit 1;

  if mapped_jc is not null and mapped_jc <> '' then
    NEW.job_card_number := mapped_jc;
  end if;

  return NEW;
end;
$_$;


