--
-- TOC entry 1910 (class 1255 OID 27702)
-- Name: parse_all_service_date_text(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.parse_all_service_date_text(v text) RETURNS date
    LANGUAGE sql IMMUTABLE
    AS $_$
  SELECT
    CASE
      WHEN nullif(btrim(v), '') ~ '^[0-9]{4}-[0-9]{2}-[0-9]{2}$'
        THEN to_date(nullif(btrim(v), ''), 'YYYY-MM-DD')
      WHEN nullif(btrim(v), '') ~ '^[0-9]{4}/[0-9]{2}/[0-9]{2}$'
        THEN to_date(nullif(btrim(v), ''), 'YYYY/MM/DD')
      WHEN nullif(btrim(v), '') ~ '^[0-9]{2}-[0-9]{2}-[0-9]{4}$'
        THEN to_date(nullif(btrim(v), ''), 'DD-MM-YYYY')
      WHEN nullif(btrim(v), '') ~ '^[0-9]{2}/[0-9]{2}/[0-9]{4}$'
        THEN to_date(nullif(btrim(v), ''), 'DD/MM/YYYY')
      ELSE NULL
    END;
$_$;


