--
-- TOC entry 1926 (class 1255 OID 28374)
-- Name: parse_date_text(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.parse_date_text(p_text text) RETURNS date
    LANGUAGE plpgsql STABLE
    AS $_$
DECLARE
  v text;
BEGIN
  v := nullif(btrim(coalesce(p_text, '')), '');

  IF v IS NULL THEN
    RETURN NULL;
  END IF;

  IF v ~ '^[0-9]{2}/[0-9]{2}/[0-9]{4}$' THEN
    RETURN to_date(v, 'DD/MM/YYYY');
  ELSIF v ~ '^[0-9]{2}/[0-9]{2}/[0-9]{2}$' THEN
    RETURN to_date(v, 'DD/MM/YY');
  ELSIF v ~ '^[0-9]{2}-[A-Za-z]{3}-[0-9]{4}$' THEN
    RETURN to_date(initcap(lower(v)), 'DD-Mon-YYYY');
  ELSIF v ~ '^[0-9]{2}-[A-Za-z]{3}-[0-9]{2}$' THEN
    RETURN to_date(initcap(lower(v)), 'DD-Mon-YY');
  ELSIF v ~ '^[0-9]{2}-[0-9]{2}-[0-9]{4}$' THEN
    RETURN to_date(v, 'DD-MM-YYYY');
  ELSIF v ~ '^[0-9]{2}-[0-9]{2}-[0-9]{2}$' THEN
    RETURN to_date(v, 'DD-MM-YY');
  ELSIF v ~ '^[0-9]{4}/[0-9]{2}/[0-9]{2}$' THEN
    RETURN to_date(v, 'YYYY/MM/DD');
  ELSIF v ~ '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' THEN
    RETURN to_date(v, 'YYYY-MM-DD');
  END IF;

  RETURN NULL;
EXCEPTION WHEN others THEN
  RETURN NULL;
END;
$_$;


--
-- TOC entry 1927 (class 1255 OID 28375)
-- Name: parse_datetime_ist(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.parse_datetime_ist(p_text text) RETURNS timestamp with time zone
    LANGUAGE plpgsql STABLE
    AS $_$
DECLARE
  v text;
  m text[];
  dd integer;
  mm integer;
  yy integer;
  hh integer;
  mi integer;
  ampm text;
  hh24 integer;
BEGIN
  v := nullif(upper(btrim(coalesce(p_text, ''))), '');

  IF v IS NULL THEN
    RETURN NULL;
  END IF;

  m := regexp_match(v, '^([0-9]{2})/([0-9]{2})/([0-9]{4})\s+([0-9]{1,2}):([0-9]{2})\s*(AM|PM)$');

  IF m IS NULL THEN
    RETURN NULL;
  END IF;

  dd := m[1]::integer;
  mm := m[2]::integer;
  yy := m[3]::integer;
  hh := m[4]::integer;
  mi := m[5]::integer;
  ampm := m[6];

  IF hh < 1 OR hh > 12 OR mi < 0 OR mi > 59 THEN
    RETURN NULL;
  END IF;

  IF ampm = 'AM' THEN
    hh24 := CASE WHEN hh = 12 THEN 0 ELSE hh END;
  ELSE
    hh24 := CASE WHEN hh = 12 THEN 12 ELSE hh + 12 END;
  END IF;

  RETURN make_timestamptz(yy, mm, dd, hh24, mi, 0, 'Asia/Kolkata');
EXCEPTION WHEN others THEN
  RETURN NULL;
END;
$_$;


