--
-- TOC entry 1967 (class 1255 OID 33663)
-- Name: parts_request_mark_seen(bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.parts_request_mark_seen(p_id bigint) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_owner uuid;
begin
  select advisor_user_id into v_owner from public.parts_requests where id = p_id;

  if v_owner is null then
    raise exception 'Parts request not found: %', p_id;
  end if;

