--
-- TOC entry 1969 (class 1255 OID 33667)
-- Name: parts_request_spm_update(bigint, text, date, text, text, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.parts_request_spm_update(p_id bigint, p_parts_number text, p_parts_order_date date, p_parts_status text, p_spm_remarks text, p_parts_qty numeric DEFAULT NULL::numeric) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_status text := btrim(coalesce(p_parts_status, ''));
begin
  if not (public.is_admin() or public.has_module_modify('parts_spm')) then
    raise exception 'Insufficient permissions';
  end if;

  if v_status = '' then
    raise exception 'Parts status is required';
  end if;

  if v_status not in (
    'Pending', 'Ordered', 'Back Order', 'In Transit',
    'Received', 'Partially Received', 'Cancelled', 'Delivered to Workshop'
  ) then
    raise exception 'Invalid parts status: %', v_status;
  end if;

  update public.parts_requests
  set parts_number = nullif(btrim(coalesce(p_parts_number, '')), ''),
      parts_order_date = p_parts_order_date,
      parts_status = v_status,
      spm_remarks = nullif(btrim(coalesce(p_spm_remarks, '')), ''),
      parts_qty = coalesce(p_parts_qty, parts_qty), -- manual override only when explicitly provided
      status_updated_at = now(),
      advisor_seen = false
  where id = p_id;

  if not found then
    raise exception 'Parts request not found: %', p_id;
  end if;
end;
$$;


--
-- TOC entry 1971 (class 1255 OID 33673)
-- Name: parts_request_update_advisor_fields(bigint, text, text, text, text, date, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.parts_request_update_advisor_fields(p_id bigint, p_registration_number text, p_parts_required text, p_parts_description text DEFAULT NULL::text, p_advisor_remarks text DEFAULT NULL::text, p_entry_date date DEFAULT NULL::date, p_parts_number text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_owner uuid;
  v_reg text := btrim(coalesce(p_registration_number, ''));
  v_parts_required text := btrim(coalesce(p_parts_required, ''));
  v_vehicle_type text;
begin
  select advisor_user_id into v_owner from public.parts_requests where id = p_id;

  if v_owner is null then
    raise exception 'Parts request not found: %', p_id;
  end if;

  if not (v_owner = auth.uid() or public.is_admin()) then
    raise exception 'Insufficient permissions';
  end if;

  if v_reg = '' then
    raise exception 'Registration number is required';
  end if;
  if v_parts_required = '' then
    raise exception 'Parts required is required';
  end if;

  select sre.portal into v_vehicle_type
  from public.service_reception_entries sre
  where upper(btrim(sre.reg_number)) = upper(v_reg)
  order by sre.created_at desc
  limit 1;

  update public.parts_requests
  set registration_number = v_reg,
      parts_required = v_parts_required,
      parts_description = nullif(btrim(coalesce(p_parts_description, '')), ''),
      advisor_remarks = nullif(btrim(coalesce(p_advisor_remarks, '')), ''),
      entry_date = coalesce(p_entry_date, entry_date),
      vehicle_type = coalesce(v_vehicle_type, vehicle_type),
      -- Advisor-supplied Parts Number is optional: only overwrite when they actually
      -- typed something. SPM/admin edits via parts_request_spm_update remain completely
      -- independent and can still correct it at any time.
      parts_number = coalesce(nullif(btrim(coalesce(p_parts_number, '')), ''), parts_number)
  where id = p_id;
end;
$$;


--
-- TOC entry 1892 (class 1255 OID 26735)
-- Name: prevent_bodyshop_reception_link_drift(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prevent_bodyshop_reception_link_drift() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF OLD.reception_entry_id IS NOT NULL THEN
    -- Block unlink of an already linked card.
    IF NEW.reception_entry_id IS NULL THEN
      RAISE EXCEPTION
        'Cannot set reception_entry_id to NULL for bodyshop_repair_cards.id=%; delete/close card with explicit workflow instead.',
        OLD.id;
    END IF;

    -- Block re-link to a different reception row.
    IF NEW.reception_entry_id IS DISTINCT FROM OLD.reception_entry_id THEN
      RAISE EXCEPTION
        'Cannot change reception_entry_id for bodyshop_repair_cards.id=% from % to %.',
        OLD.id, OLD.reception_entry_id, NEW.reception_entry_id;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


--
-- TOC entry 1936 (class 1255 OID 29247)
-- Name: process_all_service_history_sync_queue(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.process_all_service_history_sync_queue(p_batch_size integer DEFAULT 500) RETURNS TABLE(processed_count integer, remaining_due_count integer)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_rec record;
  v_processed integer := 0;
  v_batch integer := GREATEST(COALESCE(p_batch_size, 500), 1);
BEGIN
  FOR v_rec IN
    SELECT q.chassis_key
    FROM public.all_service_history_sync_queue q
    WHERE q.not_before <= now()
    ORDER BY q.not_before ASC, q.chassis_key ASC
    LIMIT v_batch
    FOR UPDATE SKIP LOCKED
  LOOP
    PERFORM public.refresh_all_service_data_from_service_history(v_rec.chassis_key);
    DELETE FROM public.all_service_history_sync_queue
    WHERE chassis_key = v_rec.chassis_key;
    v_processed := v_processed + 1;
  END LOOP;

  RETURN QUERY
  SELECT
    v_processed,
    (
      SELECT COUNT(*)::integer
      FROM public.all_service_history_sync_queue q
      WHERE q.not_before <= now()
    ) AS remaining_due_count;
END;
$$;


