    AS $$
  select case
    when p_employee_code is null then null
    when upper(p_employee_code) like '%500A840%' then 'Sitapura'
    when upper(p_employee_code) like '%3000840%' then 'Sitapura'
    when upper(p_employee_code) like '%3001440%' then 'Ajmer Road'
    else null
  end
$$;


