--
-- TOC entry 1948 (class 1255 OID 30762)
-- Name: psf_normalize_portal(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.psf_normalize_portal(p_value text) RETURNS text
    LANGUAGE sql IMMUTABLE
    AS $$
  select case
    when p_value is null or btrim(p_value) = '' then null
    when upper(btrim(p_value)) in ('PV', 'PETROL', 'ICE') then 'PV'
    when upper(btrim(p_value)) in ('EV', 'ELECTRIC') then 'EV'
    else upper(btrim(p_value))
  end
$$;


--
-- TOC entry 1947 (class 1255 OID 30761)
-- Name: psf_try_date(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.psf_try_date(p_value text) RETURNS date
    LANGUAGE plpgsql
    AS $$
begin
  if p_value is null or btrim(p_value) = '' then
    return null;
  end if;

  return btrim(p_value)::date;
exception
  when others then
    return null;
end;
$$;


--
-- TOC entry 1945 (class 1255 OID 30759)
-- Name: psf_try_numeric(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.psf_try_numeric(p_value text) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
begin
  if p_value is null or btrim(p_value) = '' then
    return null;
  end if;

  return replace(replace(replace(upper(btrim(p_value)), 'RS.', ''), ',', ''), '₹', '')::numeric;
exception
  when others then
    return null;
end;
$$;


