--
-- TOC entry 1938 (class 1255 OID 29794)
-- Name: reconcile_all_service_data_robot_flag_freshness_for_plus2_due(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reconcile_all_service_data_robot_flag_freshness_for_plus2_due() RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_rows integer := 0;
BEGIN
  UPDATE public.all_service_data AS a
  SET
    updated_by_robot = false,
    updated_by_robot_at = NULL,
    last_updated_at = now()
  WHERE a.chassis_no IS NOT NULL
    AND a.assumed_next_service_date = (current_date + 2)
    AND COALESCE(a.updated_by_robot, false) = true
    AND (
      a.updated_by_robot_at IS NULL
      OR ((a.updated_by_robot_at AT TIME ZONE 'Asia/Kolkata')::date <> (now() AT TIME ZONE 'Asia/Kolkata')::date)
    );

  GET DIAGNOSTICS v_rows = ROW_COUNT;
  RETURN v_rows;
END;
$$;


