--
-- TOC entry 1964 (class 1255 OID 33196)
-- Name: refresh_job_card_closed_dms_revenue(text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.refresh_job_card_closed_dms_revenue(p_job_card_number text, p_location text DEFAULT NULL::text, p_portal text DEFAULT NULL::text) RETURNS integer
    LANGUAGE plpgsql
    AS $$
declare
  v_updated integer := 0;
begin
  if coalesce(btrim(p_job_card_number), '') = '' then
    return 0;
  end if;

  with target as (
    select
      jc.id,
      d.final_labour_amount,
      d.total_invoice_amount
    from public.job_card_closed_data jc
    left join lateral public.latest_psf_revenue_dms_for_job_card(
      jc.job_card_number,
      jc.location,
      jc.portal
    ) d on true
    where upper(btrim(jc.job_card_number)) = upper(btrim(p_job_card_number))
      and (
        coalesce(btrim(p_location), '') = ''
        or jc.location = p_location
      )
      and (
        coalesce(btrim(p_portal), '') = ''
        or jc.portal = p_portal
      )
  )
  update public.job_card_closed_data jc
     set dms_final_labour_amount = target.final_labour_amount,
         dms_total_invoice_amount = target.total_invoice_amount
    from target
   where jc.id = target.id
     and (
       jc.dms_final_labour_amount is distinct from target.final_labour_amount
       or jc.dms_total_invoice_amount is distinct from target.total_invoice_amount
     );

  get diagnostics v_updated = row_count;
  return v_updated;
end;
$$;


--
-- TOC entry 762 (class 1255 OID 22276)
-- Name: reopen_complaint(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reopen_complaint(p_token text, p_reason text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_complaint_id bigint;
  v_dealer_code text;
  v_status text;
  v_customer_name text;
  v_priority text;
  v_resolution_mins integer;
BEGIN
  SELECT complaint_id INTO v_complaint_id
  FROM public.complaint_access_links
  WHERE token = p_token AND status = 'consumed';
  
  IF v_complaint_id IS NULL THEN
    RAISE EXCEPTION 'Invalid complaint link';
  END IF;
  
  SELECT dealer_code, status, customer_name, priority
  INTO v_dealer_code, v_status, v_customer_name, v_priority
  FROM public.complaint_tickets
  WHERE id = v_complaint_id;
  
  IF v_status NOT IN ('resolved', 'closed') THEN
    RAISE EXCEPTION 'Ticket is not in a reopenable state';
  END IF;
  
  -- Get SLA resolution time for this priority
  SELECT resolution_mins INTO v_resolution_mins
  FROM public.complaint_sla_policies
  WHERE dealer_code = v_dealer_code AND priority = v_priority;
  
  -- Reopen: status → reopened, escalate, restart resolution SLA
  UPDATE public.complaint_tickets
  SET
    status = 'reopened',
    reopened_at = now(),
    is_escalated = true,
    escalated_at = now(),
    escalation_reason = p_reason,
    resolution_due_at = now() + (COALESCE(v_resolution_mins, 1440) || ' minutes')::interval
  WHERE id = v_complaint_id;
  
  -- Log activity
  INSERT INTO public.complaint_activity (
    dealer_code, complaint_id, event_type, actor_type, actor_name, note
  ) VALUES (
    v_dealer_code, v_complaint_id, 'reopened', 'customer', v_customer_name,
    'Reopened by customer: ' || p_reason
  );
  
  -- Return updated view
  RETURN public.get_complaint_by_token(p_token);
END;
$$;


--
-- TOC entry 1972 (class 1255 OID 33794)
-- Name: reschedule_auto_service_reminder_cron(time without time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reschedule_auto_service_reminder_cron(p_send_time time without time zone) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
declare
  v_existing_job_id bigint;
  v_utc_time         time;
  v_cron             text;
begin
  if not exists (select 1 from pg_extension where extname = 'pg_cron') then
    raise notice 'pg_cron not installed — skipping reschedule for auto-service-reminder';
    return;
  end if;

  select j.jobid
  into v_existing_job_id
  from cron.job j
  where j.jobname = 'auto-service-reminder-daily-ist'
  limit 1;

  if v_existing_job_id is not null then
    perform cron.unschedule(v_existing_job_id);
  end if;

  -- Asia/Kolkata is UTC+5:30 year-round (no DST).
  v_utc_time := (p_send_time - interval '5 hours 30 minutes')::time;
  v_cron := extract(minute from v_utc_time)::int || ' ' || extract(hour from v_utc_time)::int || ' * * *';

  perform cron.schedule(
    'auto-service-reminder-daily-ist',
    v_cron,
    $job$ select public.invoke_auto_service_reminder_daily(); $job$
  );
end;
$_$;


