--
-- TOC entry 765 (class 1255 OID 22279)
-- Name: resolve(bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.resolve(p_complaint_id bigint) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_is_admin boolean := public.is_admin();
  v_dealer_code text := public.my_dealer_code();
BEGIN
  IF NOT (v_is_admin OR public.has_module_modify('complaints')) THEN
    RAISE EXCEPTION 'Insufficient permissions';
  END IF;

  IF v_is_admin THEN
    UPDATE public.complaint_tickets
    SET status = 'resolved'
    WHERE id = p_complaint_id;
  ELSE
    UPDATE public.complaint_tickets
    SET status = 'resolved'
    WHERE id = p_complaint_id
      AND dealer_code = v_dealer_code;
  END IF;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Complaint not found or not accessible';
  END IF;

  RETURN jsonb_build_object('status', 'resolved');
END;
$$;


--
-- TOC entry 1918 (class 1255 OID 27753)
-- Name: rpc_fuel_overrides(boolean, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_fuel_overrides(p_only_active boolean DEFAULT true, p_limit integer DEFAULT 100, p_offset integer DEFAULT 0) RETURNS TABLE(id bigint, match_pattern text, powertrain_type text, priority integer, is_active boolean, notes text, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NOT public.can_manage_fuel_rules() THEN
    RAISE EXCEPTION 'admin role required'
      USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  SELECT
    o.id,
    o.match_pattern,
    o.powertrain_type,
    o.priority,
    o.is_active,
    o.notes,
    o.created_at,
    o.updated_at
  FROM public.all_service_data_powertrain_overrides o
  WHERE (NOT p_only_active) OR o.is_active = true
  ORDER BY o.priority ASC, o.id ASC
  LIMIT LEAST(GREATEST(COALESCE(p_limit, 100), 1), 500)
  OFFSET GREATEST(COALESCE(p_offset, 0), 0);
END;
$$;


