--
-- TOC entry 761 (class 1255 OID 22275)
-- Name: submit_csat(text, integer, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.submit_csat(p_token text, p_rating integer, p_comment text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_complaint_id bigint;
  v_dealer_code text;
BEGIN
  SELECT complaint_id INTO v_complaint_id
  FROM public.complaint_access_links
  WHERE token = p_token AND status = 'consumed';
  
  IF v_complaint_id IS NULL THEN
    RAISE EXCEPTION 'Invalid complaint link';
  END IF;
  
  SELECT dealer_code INTO v_dealer_code
  FROM public.complaint_tickets
  WHERE id = v_complaint_id;
  
  -- Update CSAT fields
  UPDATE public.complaint_tickets
  SET csat_rating = p_rating, csat_comment = p_comment, csat_at = now()
  WHERE id = v_complaint_id;
  
  -- Log activity
  INSERT INTO public.complaint_activity (
    dealer_code, complaint_id, event_type, to_value, actor_type, actor_name
  ) VALUES (
    v_dealer_code, v_complaint_id, 'csat',
    p_rating::text, 'customer', 'customer'
  );
  
  RETURN public.get_complaint_by_token(p_token);
END;
$$;


--
-- TOC entry 1909 (class 1255 OID 27454)
-- Name: sync_all_service_data_dynamic(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_all_service_data_dynamic() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF TG_OP = 'DELETE' THEN
    DELETE FROM public.all_service_data_dynamic d
    WHERE d.id = OLD.id;
    RETURN OLD;
  END IF;

  DELETE FROM public.all_service_data_dynamic d
  WHERE d.id = NEW.id;

  IF public.is_all_service_dynamic_match(NEW) THEN
    INSERT INTO public.all_service_data_dynamic (
      id,
      chassis_no,
      vehicle_registration_number,
      model,
      product_line,
      scheduled_next_service_date,
      last_service_date,
      last_service_type,
      assumed_next_service_date,
      assumed_next_service_type,
      fuel_tp,
      sold_dealer,
      priority_bucket,
      priority_score,
      vehicle_sale_date,
      updated_by_robot,
      updated_by_robot_at
    )
    VALUES (
      NEW.id,
      NEW.chassis_no,
      NEW.vehicle_registration_number,
      NEW.model,
      NEW.product_line,
      NEW.scheduled_next_service_date,
      NEW.last_service_date,
      NEW.last_service_type,
      NEW.assumed_next_service_date,
      NEW.assumed_next_service_type,
      CASE
        WHEN upper(COALESCE(NEW.product_line, '')) LIKE '%EV%' THEN 'EV'
        ELSE 'PV'
      END,
      NEW.sold_dealer,
      public.calc_all_service_dynamic_priority_bucket(NEW.sold_dealer),
      public.calc_all_service_dynamic_priority_score(
        NEW.assumed_next_service_date,
        NEW.assumed_next_service_type,
        NEW.vehicle_sale_date::text
      ),
      NEW.vehicle_sale_date,
      NEW.updated_by_robot,
      NEW.updated_by_robot_at
    );
  END IF;

  RETURN NEW;
END;
$$;


