--
-- TOC entry 800 (class 1255 OID 24788)
-- Name: sync_bodyshop_repair_card_from_reception(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_bodyshop_repair_card_from_reception() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_is_accident boolean;
  v_job_card_no text;
  v_sa_name text;
begin
  v_is_accident := upper(trim(coalesce(new.service_type, ''))) = 'ACCIDENT';
  if not v_is_accident then
    return new;
  end if;

  v_job_card_no := upper(trim(coalesce(nullif(new.jc_number, ''), nullif(new.reg_number, ''))));
  if v_job_card_no is null or v_job_card_no = '' then
    return new;
  end if;

  v_sa_name := coalesce(nullif(trim(new.sa_display_name), ''), nullif(trim(new.sa_name), ''), null);

  update public.bodyshop_repair_cards brc
  set
    job_card_no = v_job_card_no,
    reg_number = new.reg_number,
    customer_name = new.owner_name,
    customer_phone = new.owner_phone,
    branch = new.branch,
    sa_employee_code = new.sa_employee_code,
    sa_name = coalesce(v_sa_name, brc.sa_name),
    received_at = coalesce(brc.received_at, new.created_at),
    updated_at = now()
  where brc.reception_entry_id = new.id;

  if not found then
    insert into public.bodyshop_repair_cards (
      reception_entry_id,
      job_card_no,
      reg_number,
      customer_name,
      customer_phone,
      branch,
      sa_employee_code,
      sa_name,
      current_stage,
      current_stage_name,
      overall_status,
      received_at,
      created_at,
      updated_at
    ) values (
      new.id,
      v_job_card_no,
      new.reg_number,
      new.owner_name,
      new.owner_phone,
      new.branch,
      new.sa_employee_code,
      v_sa_name,
      1,
      'Vehicle Receiving',
      'active',
      coalesce(new.created_at, now()),
      now(),
      now()
    );
  end if;

  return new;
end;
$$;


--
-- TOC entry 1894 (class 1255 OID 26924)
-- Name: sync_reception_jc_from_bodyshop_job_card(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_reception_jc_from_bodyshop_job_card() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_new_jc text;
BEGIN
  -- Only act when row is linked to reception.
  IF NEW.reception_entry_id IS NULL THEN
    RETURN NEW;
  END IF;

  v_new_jc := upper(trim(coalesce(NEW.job_card_no, '')));
  IF v_new_jc = '' THEN
    RETURN NEW;
  END IF;

  -- Mirror the existing app/database rule for valid JC format minimum length.
  IF length(v_new_jc) < 25 THEN
    RETURN NEW;
  END IF;

  UPDATE public.service_reception_entries sre
  SET jc_number = v_new_jc,
      updated_at = now()
  WHERE sre.id = NEW.reception_entry_id
    AND upper(trim(coalesce(sre.jc_number, ''))) IS DISTINCT FROM v_new_jc;

  RETURN NEW;
END;
$$;


--
-- TOC entry 798 (class 1255 OID 23721)
