CREATE FUNCTION public.telecall_get_next_assignment(p_campaign_id bigint, p_user_email text) RETURNS TABLE(asgn_id bigint, cust_id bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ DECLARE v_assignment_id BIGINT; v_customer_id BIGINT; BEGIN SELECT ta.id, ta.customer_id INTO v_assignment_id, v_customer_id FROM telecall_assignments ta WHERE ta.campaign_id = p_campaign_id AND ta.status = 'pending' AND ta.assigned_to IS NULL ORDER BY ta.priority_score DESC NULLS LAST, ta.id ASC LIMIT 1 FOR UPDATE SKIP LOCKED; IF v_assignment_id IS NOT NULL THEN UPDATE telecall_assignments SET assigned_to = p_user_email, status = 'assigned', assigned_at = NOW(), updated_at = NOW() WHERE id = v_assignment_id; RETURN QUERY SELECT v_assignment_id, v_customer_id; END IF; END; $$;


