-- TOC entry 1907 (class 1255 OID 27397)
-- Name: trg_bodyshop_stage_worklist_projection_assignment_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_bodyshop_stage_worklist_projection_assignment_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_card_id integer;
  v_job_card text;
BEGIN
  v_card_id := COALESCE(NEW.repair_card_id, OLD.repair_card_id);
  v_job_card := upper(trim(COALESCE(NEW.job_card_number, OLD.job_card_number, '')));

  IF v_card_id IS NULL AND v_job_card <> '' THEN
    SELECT brc.id
    INTO v_card_id
    FROM public.bodyshop_repair_cards brc
    WHERE upper(trim(COALESCE(brc.job_card_no, ''))) = v_job_card
    ORDER BY brc.updated_at DESC, brc.created_at DESC
    LIMIT 1;
  END IF;

  IF v_card_id IS NOT NULL THEN
    PERFORM public.recompute_bodyshop_stage_worklist_projection_for_card(v_card_id, 11, 12, 'assignment_change');
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- TOC entry 1902 (class 1255 OID 27253)
-- Name: trg_bodyshop_stage_worklist_projection_card_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_bodyshop_stage_worklist_projection_card_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
	v_from integer := 1;
	v_to integer := 18;
	v_reason text := 'fallback_full_recompute';
BEGIN
	IF TG_OP = 'INSERT' THEN
		v_from := 1;
		v_to := 18;
		v_reason := 'card_insert';
	ELSE
		IF NEW.overall_status IS DISTINCT FROM OLD.overall_status
			OR NEW.current_stage IS DISTINCT FROM OLD.current_stage
			OR NEW.current_stage_name IS DISTINCT FROM OLD.current_stage_name THEN
			v_from := 1; v_to := 18; v_reason := 'card_status_or_pointer_change';

		ELSIF NEW.customer_type IS DISTINCT FROM OLD.customer_type
			OR NEW.doc_claim_form IS DISTINCT FROM OLD.doc_claim_form
			OR NEW.doc_rc IS DISTINCT FROM OLD.doc_rc
			OR NEW.doc_insurance IS DISTINCT FROM OLD.doc_insurance
			OR NEW.doc_dl IS DISTINCT FROM OLD.doc_dl
			OR NEW.doc_aadhaar IS DISTINCT FROM OLD.doc_aadhaar
			OR NEW.doc_pan IS DISTINCT FROM OLD.doc_pan
			OR NEW.doc_kyc IS DISTINCT FROM OLD.doc_kyc
			OR NEW.doc_gst IS DISTINCT FROM OLD.doc_gst
			OR NEW.doc_company_pan IS DISTINCT FROM OLD.doc_company_pan
			OR NEW.doc_bank_detail IS DISTINCT FROM OLD.doc_bank_detail THEN
			v_from := 5; v_to := 12; v_reason := 'customer_type_or_docs_change';

		ELSIF NEW.estimated_amount IS DISTINCT FROM OLD.estimated_amount THEN
			v_from := 6; v_to := 12; v_reason := 'estimated_amount_change';

		ELSIF NEW.estimation_approved_by IS DISTINCT FROM OLD.estimation_approved_by THEN
			v_from := 7; v_to := 12; v_reason := 'estimation_approved_by_change';

		ELSIF NEW.claim_intimation_no IS DISTINCT FROM OLD.claim_intimation_no THEN
			v_from := 8; v_to := 12; v_reason := 'claim_intimation_change';

		ELSIF NEW.survey_date IS DISTINCT FROM OLD.survey_date
			OR NEW.survey_status IS DISTINCT FROM OLD.survey_status
			OR NEW.survey_hold_reason IS DISTINCT FROM OLD.survey_hold_reason THEN
			v_from := 9; v_to := 12; v_reason := 'survey_fields_change';

		ELSIF NEW.approved_parts IS DISTINCT FROM OLD.approved_parts THEN
			v_from := 10; v_to := 12; v_reason := 'approved_parts_change';

		ELSIF NEW.additional_approval IS DISTINCT FROM OLD.additional_approval THEN
			v_from := 11; v_to := 12; v_reason := 'additional_approval_change';

		ELSIF NEW.bodyshop_floor IS DISTINCT FROM OLD.bodyshop_floor
			OR NEW.floor_status IS DISTINCT FROM OLD.floor_status
			OR NEW.floor_hold_reason IS DISTINCT FROM OLD.floor_hold_reason THEN
			v_from := 9; v_to := 12; v_reason := 'floor_assignment_change';
		END IF;
	END IF;

	PERFORM public.recompute_bodyshop_stage_worklist_projection_for_card(NEW.id, v_from, v_to, v_reason);
	RETURN NEW;
END;
$$;


--
-- TOC entry 1903 (class 1255 OID 27255)
-- Name: trg_bodyshop_stage_worklist_projection_doc_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_bodyshop_stage_worklist_projection_doc_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
	v_repair_card_id integer;
	v_doc_key text;
BEGIN
	IF TG_OP = 'DELETE' THEN
		v_repair_card_id := OLD.repair_card_id;
		v_doc_key := OLD.doc_key;
	ELSE
		v_repair_card_id := NEW.repair_card_id;
		v_doc_key := NEW.doc_key;
	END IF;

	IF v_repair_card_id IS NULL THEN
		RETURN COALESCE(NEW, OLD);
	END IF;

	IF v_doc_key = 'doc_survey_approval' THEN
		PERFORM public.recompute_bodyshop_stage_worklist_projection_for_card(
			v_repair_card_id,
			10,
			12,
			'doc_survey_approval_change'
		);
	END IF;

	RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- TOC entry 1886 (class 1255 OID 26076)
-- Name: trg_cn_write_notifications_fn(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_cn_write_notifications_fn() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_assigned_email text;
BEGIN
  -- New complaint raised: notify assigned staff in-app/email, admin shared inbox in-app, and customer sms.
  IF TG_OP = 'INSERT' THEN
    IF NEW.assigned_to IS NOT NULL THEN
      INSERT INTO public.complaint_notifications (
        dealer_code, complaint_id, event_type, recipient_type, recipient_user_id, channel, payload
      ) VALUES (
        NEW.dealer_code,
        NEW.id,
        'raised',
        'staff',
        NEW.assigned_to,
        'in_app',
        jsonb_build_object('ticket_number', NEW.ticket_number, 'title', NEW.title, 'branch', NEW.branch)
      );
    END IF;

    INSERT INTO public.complaint_notifications (
      dealer_code, complaint_id, event_type, recipient_type, channel, payload
    ) VALUES (
      NEW.dealer_code,
      NEW.id,
      'raised',
      'admin',
      'in_app',
      jsonb_build_object('ticket_number', NEW.ticket_number, 'title', NEW.title, 'branch', NEW.branch)
    );

    SELECT u.email INTO v_assigned_email
    FROM public.users u
    WHERE u.id = NEW.assigned_to;

    IF v_assigned_email IS NOT NULL THEN
      INSERT INTO public.complaint_notifications (
        dealer_code, complaint_id, event_type, recipient_type, recipient_email, channel, payload
      ) VALUES (
        NEW.dealer_code,
        NEW.id,
        'raised',
        'staff',
        v_assigned_email,
        'email',
        jsonb_build_object('ticket_number', NEW.ticket_number, 'branch', NEW.branch)
      );
    END IF;

    IF NEW.customer_phone IS NOT NULL THEN
      INSERT INTO public.complaint_notifications (
        dealer_code, complaint_id, event_type, recipient_type, recipient_phone, channel, payload
      ) VALUES (
        NEW.dealer_code,
        NEW.id,
        'raised',
        'customer',
        NEW.customer_phone,
        'sms',
        jsonb_build_object('ticket_number', NEW.ticket_number, 'status', NEW.status)
      );
    END IF;

    RETURN NEW;
  END IF;

  -- Status transitions: notify customer via sms, assigned staff in-app, and admin shared inbox in-app.
  IF NEW.status IS DISTINCT FROM OLD.status THEN
    IF NEW.customer_phone IS NOT NULL THEN
      INSERT INTO public.complaint_notifications (
        dealer_code, complaint_id, event_type, recipient_type, recipient_phone, channel, payload
      ) VALUES (
        NEW.dealer_code,
        NEW.id,
        NEW.status,
        'customer',
        NEW.customer_phone,
        'sms',
        jsonb_build_object('ticket_number', NEW.ticket_number, 'from_status', OLD.status, 'to_status', NEW.status)
      );
    END IF;

    IF NEW.assigned_to IS NOT NULL THEN
      INSERT INTO public.complaint_notifications (
        dealer_code, complaint_id, event_type, recipient_type, recipient_user_id, channel, payload
      ) VALUES (
        NEW.dealer_code,
        NEW.id,
        NEW.status,
        'staff',
        NEW.assigned_to,
        'in_app',
        jsonb_build_object('ticket_number', NEW.ticket_number, 'from_status', OLD.status, 'to_status', NEW.status)
      );
    END IF;

    INSERT INTO public.complaint_notifications (
      dealer_code, complaint_id, event_type, recipient_type, channel, payload
    ) VALUES (
      NEW.dealer_code,
      NEW.id,
      NEW.status,
      'admin',
      'in_app',
      jsonb_build_object('ticket_number', NEW.ticket_number, 'from_status', OLD.status, 'to_status', NEW.status)
    );
  END IF;

  -- Escalation transitions: notify manager email, assigned staff in-app, and admin shared inbox in-app.
  IF NEW.is_escalated IS DISTINCT FROM OLD.is_escalated AND NEW.is_escalated = true THEN
    INSERT INTO public.complaint_notifications (
      dealer_code, complaint_id, event_type, recipient_type, channel, payload
    ) VALUES (
      NEW.dealer_code,
      NEW.id,
      'escalated',
      'manager',
      'email',
      jsonb_build_object('ticket_number', NEW.ticket_number, 'reason', NEW.escalation_reason)
    );

    IF NEW.assigned_to IS NOT NULL THEN
      INSERT INTO public.complaint_notifications (
        dealer_code, complaint_id, event_type, recipient_type, recipient_user_id, channel, payload
      ) VALUES (
        NEW.dealer_code,
        NEW.id,
        'escalated',
        'staff',
        NEW.assigned_to,
        'in_app',
        jsonb_build_object('ticket_number', NEW.ticket_number, 'reason', NEW.escalation_reason)
      );
    END IF;

    INSERT INTO public.complaint_notifications (
      dealer_code, complaint_id, event_type, recipient_type, channel, payload
    ) VALUES (
      NEW.dealer_code,
      NEW.id,
      'escalated',
      'admin',
      'in_app',
      jsonb_build_object('ticket_number', NEW.ticket_number, 'reason', NEW.escalation_reason)
    );
  END IF;

  -- Reassignment: notify newly assigned staff in-app/email and admin shared inbox in-app.
  IF NEW.assigned_to IS DISTINCT FROM OLD.assigned_to THEN
    IF NEW.assigned_to IS NOT NULL THEN
      INSERT INTO public.complaint_notifications (
        dealer_code, complaint_id, event_type, recipient_type, recipient_user_id, channel, payload
      ) VALUES (
        NEW.dealer_code,
        NEW.id,
        'reassigned',
        'staff',
        NEW.assigned_to,
        'in_app',
        jsonb_build_object('ticket_number', NEW.ticket_number, 'assigned_to', NEW.assigned_to)
      );
    END IF;

    INSERT INTO public.complaint_notifications (
      dealer_code, complaint_id, event_type, recipient_type, channel, payload
    ) VALUES (
      NEW.dealer_code,
      NEW.id,
      'reassigned',
      'admin',
      'in_app',
      jsonb_build_object('ticket_number', NEW.ticket_number, 'assigned_to', NEW.assigned_to)
    );

    SELECT u.email INTO v_assigned_email
    FROM public.users u
    WHERE u.id = NEW.assigned_to;

    IF v_assigned_email IS NOT NULL THEN
      INSERT INTO public.complaint_notifications (
        dealer_code, complaint_id, event_type, recipient_type, recipient_email, channel, payload
      ) VALUES (
        NEW.dealer_code,
        NEW.id,
        'reassigned',
        'staff',
        v_assigned_email,
        'email',
        jsonb_build_object('ticket_number', NEW.ticket_number, 'assigned_to', NEW.assigned_to)
      );
    END IF;
  END IF;

  RETURN NEW;
EXCEPTION
  WHEN OTHERS THEN
    RAISE NOTICE 'complaint_notifications outbox write skipped: %', SQLERRM;
    RETURN NEW;
END;
$$;


--
-- TOC entry 754 (class 1255 OID 22260)
-- Name: trg_ct_autoassign_fn(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_ct_autoassign_fn() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_sa_code text;
  v_assigned_user_id uuid;
BEGIN
  -- Get the SA employee code from the linked reception entry
  SELECT sa_employee_code INTO v_sa_code
  FROM public.service_reception_entries
  WHERE id = NEW.reception_entry_id;
  
  IF v_sa_code IS NOT NULL THEN
    NEW.sa_employee_code := v_sa_code;
    
    -- Resolve the user ID from user_employee_links
    -- Note: user_employee_links has NO deleted_at column (verified from schema audit)
    SELECT user_id INTO v_assigned_user_id
    FROM public.user_employee_links
    WHERE employee_code = v_sa_code
      AND is_primary = true
      AND is_active = true
      AND dealer_code = NEW.dealer_code
    LIMIT 1;
    
    NEW.assigned_to := v_assigned_user_id;  -- may be NULL if advisor not found
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- TOC entry 757 (class 1255 OID 22267)
-- Name: trg_ct_history_fn(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_ct_history_fn() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- On status change
  IF OLD.status IS DISTINCT FROM NEW.status THEN
    INSERT INTO public.complaint_activity (
      dealer_code, complaint_id, event_type, from_value, to_value,
      actor_type, actor_id, actor_name
    ) VALUES (
      NEW.dealer_code,
      NEW.id,
      'status_change',
      OLD.status,
      NEW.status,
      'staff',
      auth.uid(),
      COALESCE(auth.jwt()->>'email', 'system')
    );
    
    -- Stamp milestone timestamps
    IF NEW.status = 'acknowledged' AND OLD.status IN ('new') THEN
      NEW.first_response_at := now();
    END IF;
    IF NEW.status = 'resolved' AND OLD.status != 'resolved' THEN
      NEW.resolved_at := now();
    END IF;
    IF NEW.status = 'closed' THEN
      NEW.closed_at := now();
    END IF;
    IF NEW.status = 'reopened' THEN
      NEW.reopened_at := now();
    END IF;
  END IF;
  
  -- On assignment change
  IF OLD.assigned_to IS DISTINCT FROM NEW.assigned_to THEN
    INSERT INTO public.complaint_activity (
      dealer_code, complaint_id, event_type, from_value, to_value,
      actor_type, actor_id, actor_name
    ) VALUES (
      NEW.dealer_code,
      NEW.id,
      'assigned',
      OLD.assigned_to::text,
      NEW.assigned_to::text,
      'staff',
      auth.uid(),
      COALESCE(auth.jwt()->>'email', 'system')
    );
  END IF;
  
  -- On escalation change
  IF OLD.is_escalated IS DISTINCT FROM NEW.is_escalated THEN
    IF NEW.is_escalated = true THEN
      NEW.escalated_at := now();
      INSERT INTO public.complaint_activity (
        dealer_code, complaint_id, event_type, note,
        actor_type, actor_name
      ) VALUES (
        NEW.dealer_code,
        NEW.id,
        'escalated',
        NEW.escalation_reason,
        'staff',
        COALESCE(auth.jwt()->>'email', 'system')
      );
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- TOC entry 755 (class 1255 OID 22262)
-- Name: trg_ct_sla_fn(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_ct_sla_fn() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_response_mins integer;
  v_resolution_mins integer;
BEGIN
  -- Fetch SLA targets for the ticket's dealer and priority
  SELECT response_mins, resolution_mins
  INTO v_response_mins, v_resolution_mins
  FROM public.complaint_sla_policies
  WHERE dealer_code = NEW.dealer_code
    AND priority = NEW.priority;
  
  IF v_response_mins IS NOT NULL THEN
    NEW.response_due_at := now() + (v_response_mins || ' minutes')::interval;
  END IF;
  
  IF v_resolution_mins IS NOT NULL THEN
    NEW.resolution_due_at := now() + (v_resolution_mins || ' minutes')::interval;
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- TOC entry 753 (class 1255 OID 22258)
-- Name: trg_ct_ticket_number_fn(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_ct_ticket_number_fn() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
  v_dealer_abbr text;
  v_branch_code text;
  v_fiscal_year text;
  v_seq bigint;
BEGIN
  -- Extract dealer abbreviation (first 6 chars, typically FstMbl)
  v_dealer_abbr := SUBSTRING(NEW.dealer_code FROM 1 FOR 6);
  
  -- Extract branch code (3-char abbreviation, e.g., FQ7, or default to XX)
  v_branch_code := COALESCE(
    SUBSTRING(NEW.branch FROM 1 FOR 3),
    'XX'
  );
  
  -- Fiscal year (2626 format: 2026-27 → 2627)
  -- TODO: Replace with dynamic computation if fiscal year logic differs in your codebase
  v_fiscal_year := '2627';
  
  -- Get next sequence number for this dealer
  -- Increments per dealer; use MAX of existing + 1
  SELECT COALESCE(
    MAX(
      SUBSTRING(ticket_number FROM '([0-9]+)$')::bigint
    ),
    0
  ) + 1
  INTO v_seq
  FROM public.complaint_tickets
  WHERE dealer_code = NEW.dealer_code;
  
  -- Construct ticket number: CMP-FstMbl-FQ7-2627-000118
  NEW.ticket_number := FORMAT('CMP-%s-%s-%s-%06s',
    v_dealer_abbr, v_branch_code, v_fiscal_year, v_seq);
  
  RETURN NEW;
END;
$_$;


