--
-- TOC entry 1943 (class 1255 OID 30316)
-- Name: upsert_all_service_data_from_booking_source(text, date, text, text, text, text, date, text, text, timestamp with time zone, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.upsert_all_service_data_from_booking_source(p_chassis_no text, p_vehicle_sale_date date DEFAULT NULL::date, p_engine_no text DEFAULT NULL::text, p_contact_phones text DEFAULT NULL::text, p_first_name text DEFAULT NULL::text, p_last_insurance_comapny text DEFAULT NULL::text, p_last_insurance_expiry_date date DEFAULT NULL::date, p_model text DEFAULT NULL::text, p_product_line text DEFAULT NULL::text, p_source_updated_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_source_row_id text DEFAULT NULL::text) RETURNS TABLE(action text, target_id bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_chassis_norm text;
  v_chassis_raw text;
  v_engine_no text;
  v_contact_phones text;
  v_first_name text;
  v_last_insurance_comapny text;
  v_model text;
  v_product_line text;
  v_target_id bigint;
begin
  v_chassis_raw := nullif(btrim(p_chassis_no), '');
  v_chassis_norm := upper(v_chassis_raw);
  v_engine_no := nullif(btrim(p_engine_no), '');
  v_contact_phones := nullif(btrim(p_contact_phones), '');
  v_first_name := nullif(btrim(p_first_name), '');
  v_last_insurance_comapny := nullif(btrim(p_last_insurance_comapny), '');
  v_model := nullif(btrim(p_model), '');
  v_product_line := nullif(btrim(p_product_line), '');

  if v_chassis_norm is null then
    return query select 'skipped_no_chassis'::text, null::bigint;
    return;
  end if;

  -- Hard gate (core fields): insert only when all core mapped values are present.
  if p_vehicle_sale_date is null
    or v_engine_no is null
    or v_contact_phones is null
    or v_first_name is null
    or v_last_insurance_comapny is null
    or p_last_insurance_expiry_date is null
    or p_source_updated_at is null
  then
    return query select 'skipped_missing_core_fields'::text, null::bigint;
    return;
  end if;

  select t.id
  into v_target_id
  from public.all_service_data t
  where upper(nullif(btrim(t.chassis_no), '')) = v_chassis_norm
  order by t.last_updated_at desc nulls last, t.id desc
  limit 1;

  if v_target_id is not null then
    return query select 'skipped_existing_chassis'::text, v_target_id;
    return;
  end if;

  insert into public.all_service_data (
    chassis_no,
    vehicle_sale_date,
    engine_no,
    contact_phones,
    first_name,
    last_insurance_comapny,
    last_insurance_expiry_date,
    model,
    product_line,
    sold_dealer,
    updated_by_sale,
    updated_by_sale_at,
    last_service_type,
    last_service_date,
    created_at,
    last_updated_at
  )
  values (
    v_chassis_raw,
    p_vehicle_sale_date,
    v_engine_no,
    v_contact_phones,
    v_first_name,
    v_last_insurance_comapny,
    p_last_insurance_expiry_date,
    v_model,
    v_product_line,
    'Techwheels',
    true,
    now(),
    'New',
    (p_vehicle_sale_date::timestamp at time zone 'Asia/Kolkata'),
    now(),
    now()
  )
  returning id into v_target_id;

  return query select 'inserted'::text, v_target_id;
end;
$$;


