--
-- TOC entry 568 (class 1259 OID 29380)
-- Name: job_card_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.job_card_summary AS
 SELECT jc.id AS job_card_id,
    jc.jc_number,
    jc.complaint_date,
    jc.km_reading,
    jc.claim_type,
    jc.complaint_text,
    jc.status,
    jc.gdc_status,
    jc.claim_submitted_at,
    jc.claim_submitted_by,
    jc.claim_hidden,
    jc.created_at AS jc_created_at,
    jc.updated_at AS jc_updated_at,
    v.reg_number,
    v.vin,
    v.model,
    v.year AS vehicle_year,
    v.colour,
    v.paint_type,
    v.dealer_code,
    v.dealer_name,
    v.dealer_city,
    v.bp_city_category,
    v.owner_name,
    v.owner_phone,
    v.date_of_sale,
        CASE
            WHEN (v.date_of_sale IS NOT NULL) THEN (CURRENT_DATE - v.date_of_sale)
            ELSE NULL::integer
        END AS warranty_age_days,
        CASE
            WHEN (v.date_of_sale IS NULL) THEN NULL::integer
            WHEN ((CURRENT_DATE - v.date_of_sale) <= 365) THEN 100
            WHEN ((CURRENT_DATE - v.date_of_sale) <= 730) THEN 50
            WHEN ((CURRENT_DATE - v.date_of_sale) <= 1095) THEN 25
            ELSE 0
        END AS tml_share_percent,
    count(DISTINCT p.id) AS panel_count,
    count(DISTINCT ph.id) AS photo_count,
    count(DISTINCT d.id) AS document_count,
    count(DISTINCT er.id) AS estimate_row_count,
    COALESCE(sum(er.row_total), (0)::numeric) AS total_estimate_amount,
        CASE
            WHEN (v.date_of_sale IS NULL) THEN (0)::numeric
            WHEN ((CURRENT_DATE - v.date_of_sale) <= 365) THEN round((COALESCE(sum(er.row_total), (0)::numeric) * 1.0))
            WHEN ((CURRENT_DATE - v.date_of_sale) <= 730) THEN round((COALESCE(sum(er.row_total), (0)::numeric) * 0.5))
            WHEN ((CURRENT_DATE - v.date_of_sale) <= 1095) THEN round((COALESCE(sum(er.row_total), (0)::numeric) * 0.25))
            ELSE (0)::numeric
        END AS tml_share_amount,
    bool_or((ph.photo_type = 'defect'::public.photo_type)) AS has_defect_photos,
    bool_or((ph.photo_type = 'primer'::public.photo_type)) AS has_primer_photos,
    bool_or((ph.photo_type = 'paint'::public.photo_type)) AS has_paint_photos,
    bool_or((d.doc_type = 'service_history'::public.doc_type)) AS has_service_history,
    bool_or((d.doc_type = 'video_job_card'::public.doc_type)) AS has_video_job_card,
    bool_or((d.doc_type = 'video_delivery'::public.doc_type)) AS has_video_delivery,
    bool_or((d.doc_type = 'ppt_pre'::public.doc_type)) AS has_ppt_pre,
    bool_or((d.doc_type = 'ppt_post'::public.doc_type)) AS has_ppt_post,
    bool_or((d.doc_type = 'excel_estimate'::public.doc_type)) AS has_excel_estimate,
    array_agg(DISTINCT p.panel_name) FILTER (WHERE (p.panel_name IS NOT NULL)) AS panel_names
   FROM (((((public.job_cards jc
     JOIN public.vehicles v ON ((v.reg_number = jc.reg_number)))
     LEFT JOIN public.panels p ON ((p.job_card_id = jc.id)))
     LEFT JOIN public.panel_photos ph ON ((ph.job_card_id = jc.id)))
     LEFT JOIN public.estimate_rows er ON ((er.job_card_id = jc.id)))
     LEFT JOIN public.documents d ON ((d.job_card_id = jc.id)))
  GROUP BY jc.id, jc.jc_number, jc.complaint_date, jc.km_reading, jc.claim_type, jc.complaint_text, jc.status, jc.gdc_status, jc.claim_submitted_at, jc.claim_submitted_by, jc.claim_hidden, jc.created_at, jc.updated_at, v.reg_number, v.vin, v.model, v.year, v.colour, v.paint_type, v.dealer_code, v.dealer_name, v.dealer_city, v.bp_city_category, v.owner_name, v.owner_phone, v.date_of_sale;


