--
-- TOC entry 586 (class 1259 OID 32611)
-- Name: post_service_feedback_cre_queue; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.post_service_feedback_cre_queue AS
 SELECT m.id,
    m.job_card_closed_data_id,
    m.customer_name,
    m.mobile_number,
    m.vehicle_registration_number,
    m.job_card_number,
    m.closed_date,
    m.rating,
    m.feedback_text,
    m.responded_at,
    m.cre_status,
    m.resolved_at,
    m.resolved_by_name,
    COALESCE(em.employee_name, jc.sr_assigned_to) AS service_advisor_name,
    jc.sr_type AS service_type,
    m.review_link_sent,
    jc.branch_label AS branch
   FROM ((public.post_service_feedback_messages m
     LEFT JOIN public.job_card_closed_data jc ON ((jc.id = m.job_card_closed_data_id)))
     LEFT JOIN public.employee_master em ON ((em.employee_code = jc.employee_code)))
  WHERE ((m.status = 'responded'::text) AND (m.rating IS NOT NULL));


