-- Name: VIEW post_service_feedback_cre_queue; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.post_service_feedback_cre_queue IS 'All responded post-service feedback (any rating), joined to the resolved Service Advisor name, service type, and branch. Frontend splits into "needs follow-up" (<=3) vs "positive" (>=4) tabs.';


