     JOIN public.bodyshop_repair_cards c ON ((c.id = p.repair_card_id)));


--
-- TOC entry 421 (class 1259 OID 18136)
-- Name: vw_parts_stock_health; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_parts_stock_health WITH (security_invoker='true') AS
 WITH latest_snapshot AS (
         SELECT service_parts_stock_snapshot_data.branch,
            service_parts_stock_snapshot_data.portal,
            max(service_parts_stock_snapshot_data.snapshot_date) AS snapshot_date
           FROM public.service_parts_stock_snapshot_data
          GROUP BY service_parts_stock_snapshot_data.branch, service_parts_stock_snapshot_data.portal
        ), latest_stock AS (
         SELECT s_1.part_number,
            s_1.part_description,
            s_1.branch,
            s_1.portal,
            s_1.on_hand_quantity,
            s_1.location_1,
            s_1.inventory_location,
            s_1.total_price_value,
            s_1.availability_status,
            s_1.status,
            p.vendor,
            p.category AS product_category
           FROM ((public.service_parts_stock_snapshot_data s_1
             LEFT JOIN public.part_master p ON ((s_1.part_number = p.part_number)))
             JOIN latest_snapshot ls ON (((s_1.branch = ls.branch) AND (s_1.portal = ls.portal) AND (s_1.snapshot_date = ls.snapshot_date))))
        ), avg_consumption AS (
         SELECT service_parts_consumption_data.part_number,
            service_parts_consumption_data.branch,
            service_parts_consumption_data.portal,
            round(avg(service_parts_consumption_data.total_consumption), 2) AS avg_4week_consumption
           FROM public.service_parts_consumption_data
          WHERE ((service_parts_consumption_data.total_consumption > (0)::numeric) AND (service_parts_consumption_data.created_at > (now() - '28 days'::interval)))
          GROUP BY service_parts_consumption_data.part_number, service_parts_consumption_data.branch, service_parts_consumption_data.portal
        ), active_orders AS (
         SELECT service_parts_order_data.part_number,
            service_parts_order_data.branch,
            service_parts_order_data.portal,
            sum(COALESCE(service_parts_order_data.intransit_qty, (0)::numeric)) AS intransit_qty,
            min(COALESCE(service_parts_order_data.eta_1, service_parts_order_data.eta_2, service_parts_order_data.eta_3)) AS nearest_eta
           FROM public.service_parts_order_data
          WHERE (COALESCE(service_parts_order_data.order_status, ''::text) <> 'Received'::text)
          GROUP BY service_parts_order_data.part_number, service_parts_order_data.branch, service_parts_order_data.portal
        ), last_issue AS (
         SELECT service_parts_stock_snapshot_data.part_number,
            service_parts_stock_snapshot_data.branch,
            max(service_parts_stock_snapshot_data.last_issue_date) AS last_issue_date
           FROM public.service_parts_stock_snapshot_data
          GROUP BY service_parts_stock_snapshot_data.part_number, service_parts_stock_snapshot_data.branch
        ), consumption_totals AS (
         SELECT service_parts_consumption_data.part_number,
            service_parts_consumption_data.branch,
            sum(COALESCE(service_parts_consumption_data.otc_quantity, (0)::numeric)) AS otc_total,
            sum(COALESCE(service_parts_consumption_data.ws_quantity, (0)::numeric)) AS ws_total
           FROM public.service_parts_consumption_data
          GROUP BY service_parts_consumption_data.part_number, service_parts_consumption_data.branch
        )
 SELECT s.part_number,
    s.part_description,
    s.branch,
    s.portal,
    s.on_hand_quantity,
    ac.avg_4week_consumption,
        CASE
            WHEN (ac.avg_4week_consumption > (0)::numeric) THEN round(((s.on_hand_quantity / ac.avg_4week_consumption) * (7)::numeric), 2)
            ELSE (0)::numeric
        END AS days_of_supply,
        CASE
            WHEN (ac.avg_4week_consumption > (0)::numeric) THEN round((s.on_hand_quantity / (ac.avg_4week_consumption / (4)::numeric)), 2)
            ELSE (0)::numeric
        END AS weeks_of_supply,
    COALESCE(ao.intransit_qty, (0)::numeric) AS intransit_qty,
    ao.nearest_eta,
    s.location_1,
    s.inventory_location,
    s.total_price_value,
    s.vendor,
    s.product_category,
    s.availability_status,
    s.status,
    li.last_issue_date,
    COALESCE(ct.otc_total, (0)::numeric) AS otc_total,
    COALESCE(ct.ws_total, (0)::numeric) AS ws_total,
    ((li.last_issue_date IS NULL) OR (li.last_issue_date < (now() - '90 days'::interval))) AS is_dead_stock,
    (s.on_hand_quantity / NULLIF((ac.avg_4week_consumption * 4.33), (0)::numeric)) AS months_of_stock
   FROM ((((latest_stock s
     LEFT JOIN avg_consumption ac ON (((s.part_number = ac.part_number) AND (s.branch = ac.branch) AND (s.portal = ac.portal))))
     LEFT JOIN active_orders ao ON (((s.part_number = ao.part_number) AND (s.branch = ao.branch) AND (s.portal = ao.portal))))
     LEFT JOIN last_issue li ON (((s.part_number = li.part_number) AND (s.branch = li.branch))))
     LEFT JOIN consumption_totals ct ON (((s.part_number = ct.part_number) AND (s.branch = ct.branch))));


