-- TOC entry 7844 (class 3256 OID 22016)
-- Name: email_logs Users can view email logs for their dealer's job cards; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY "Users can view email logs for their dealer's job cards" ON public.email_logs FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM (public.job_cards jc
     JOIN public.vehicles v ON ((v.reg_number = jc.reg_number)))
  WHERE ((jc.id = email_logs.job_card_id) AND public.dealer_code_in_scope(v.dealer_code)))));


